/* Ambiotica sample-rate scaling helpers (Phase 1).
 *
 * The DSP was authored with all time-based constants expressed as sample
 * counts / one-pole coefficients at 44.1 kHz. These helpers rescale those
 * reference values to the host rate.
 *
 * Bit-for-bit parity contract: at exactly 44.1 kHz every helper returns the
 * original reference value unchanged (the `== AMB_REF_SAMPLE_RATE` guard),
 * so 44.1 kHz output is identical to the pre-refactor DSP.
 */
#ifndef AMBIOTICA_RATE_UTIL_H
#define AMBIOTICA_RATE_UTIL_H


#define AMB_REF_SAMPLE_RATE 44100.0

/* A sample count defined at 44.1 kHz, rescaled to `sr` and rounded to nearest.
 * Exact at the reference rate (no rounding drift). */
static inline int amb_scale_samples(double ref_samples_at_44k, double sr) {
    if (sr == AMB_REF_SAMPLE_RATE) return (int)(ref_samples_at_44k + 0.5);
    return (int)(ref_samples_at_44k * (sr / AMB_REF_SAMPLE_RATE) + 0.5);
}

/* Same, keeping fractional precision — for sub-sample quantities like the
 * reverb's modulation depth in samples. */
static inline float amb_scale_samples_f(double ref_samples_at_44k, double sr) {
    if (sr == AMB_REF_SAMPLE_RATE) return (float)ref_samples_at_44k;
    return (float)(ref_samples_at_44k * (sr / AMB_REF_SAMPLE_RATE));
}

/* Rescale a one-pole coefficient a = exp(-2*pi*fc/fs) to a new rate while
 * preserving its cutoff / time constant:  a' = a ^ (ref_sr / sr).
 * Exact at the reference rate. */
static inline float amb_scale_onepole(float ref_coef_at_44k, double sr) {
    if (sr == AMB_REF_SAMPLE_RATE) return ref_coef_at_44k;
    return powf(ref_coef_at_44k, (float)(AMB_REF_SAMPLE_RATE / sr));
}

#endif /* AMBIOTICA_RATE_UTIL_H */
/* Fast float approximations of transcendentals, for the RP2350 (Cortex-M33 has
 * no hardware trig; software sinf/cosf/tanhf/powf cost hundreds of cycles each,
 * which blows the ~2 ms core0 DSP budget when called per-sample). Accuracy here
 * is "inaudible in a modulation/window/waveshaper", not scientific.
 *
 * Used to replace ONLY the per-sample (hot-loop) calls in the chain. Per-block
 * / setup calls (the *_set_* coefficient updates, *_create) keep the exact libm versions.
 */
#ifndef AMB_FAST_MATH_H
#define AMB_FAST_MATH_H

/* tanh via Padé-3, bounded to +/-1 (same shape as looper's soft_sat). ~5 flops. */
static inline float fast_tanhf(float x) {
    if (x >  3.0f) return  1.0f;
    if (x < -3.0f) return -1.0f;
    float x2 = x * x;
    return x * (27.0f + x2) / (27.0f + 9.0f * x2);
}

/* sin via range-reduction to [-pi,pi] + Bhaskara parabola with one correction.
 * EXACT at 0, +/-pi/2, +/-pi and ~9e-4 max error elsewhere. The endpoint exactness is
 * REQUIRED, not incidental: grain / crossfade windows are built from sin()/cos() and
 * must reach 0 and 1 exactly at their edges, or every window is warped and clicks at
 * the grain rate. Don't swap in a cheaper polynomial that overshoots near +/-pi. */
static inline float fast_sinf(float x) {
    const float TWO_PI = 6.28318530718f, INV_TWO_PI = 0.15915494309f, PI = 3.14159265359f;
    float k = x * INV_TWO_PI;
    k = k - (float)(int)(k + (k >= 0.0f ? 0.5f : -0.5f));   /* frac to [-0.5,0.5] */
    float t = k * TWO_PI;                                    /* t to [-pi,pi] */
    const float B = 4.0f / PI, C = -4.0f / (PI * PI);
    float at = t < 0.0f ? -t : t;
    float y = B * t + C * t * at;                           /* parabola: 0 at 0,+/-pi; +/-1 at +/-pi/2 */
    float ay = y < 0.0f ? -y : y;
    return 0.225f * (y * ay - y) + y;                       /* correction -> ~9e-4 err */
}
static inline float fast_cosf(float x) { return fast_sinf(x + 1.57079632679f); }

/* 2^x approx (only needed by granular pitch mod). Bit-trick exponent + poly. */
static inline float fast_exp2f(float x) {
    if (x >  30.0f) x =  30.0f;
    if (x < -30.0f) x = -30.0f;
    float fl = (float)(int)(x >= 0.0f ? x : x - 1.0f);      /* floor */
    float xf = x - fl;
    float p = 1.0f + xf * (0.6931472f + xf * (0.2402265f + xf * 0.0555041f));
    union { float f; unsigned int u; } v; v.f = p;
    v.u += ((unsigned int)(int)fl) << 23;                   /* * 2^floor(x) */
    return v.f;
}

#endif
