static const int FC_CHORD_SEMIS[5][4] = {
    {12,16,19,-1},   /* Ionian / major    -> C3 E3  G3 */
    {12,15,19,-1},   /* Aeolian / minor   -> C3 Eb3 G3 */
    {12,15,21,-1},   /* Dorian            -> C3 Eb3 A3  (minor + nat 6) */
    {12,16,19,-1},   /* Lydian (major)    -> C3 E3  G3 */
    {12,16,22,-1}    /* Mixolydian        -> C3 E3  Bb3 (major + b7) */
};
static int fc_build_chord(int key, int chord, float* out) {
    if (key < 0) key = 0; if (key > 11) key = 11;
    if (chord < 0) chord = 0; if (chord > 4) chord = 4;
    const int root = 36 + key;                   /* C2 + key (matches buildChordFreqs) */
    int n = 0;
    for (int i = 0; i < 4; i++) { int s = FC_CHORD_SEMIS[chord][i]; if (s < 0) break;
        out[n++] = 440.0f * powf(2.0f, (float)(root + s - 69) / 12.0f); }
    return n;
}

static void fc_init(fc_state* st, float mix) { memset(st, 0, sizeof(*st)); st->mixCur = mix; }

/* Push all param-derived coefficients into the modules. Called only when params change
 * (and throttled during ramps — see fc_render_block), since it runs many setters. The
 * reverb (Dattorro) is configured in the reverb stage itself, not here. */
static void fc_push_params(looper_t* l, granular_t* g, microloop_t* m,
                           harmony_t* h, bloom_t* b, drift_t* d, const full_params* p, double sr) {
    double bpm = p->bpm > 0 ? p->bpm : 120.0;
    float bars = p->loop_length_bars; if (bars < 0.5f) bars = 0.5f; if (bars > 8) bars = 8;
    looper_set_loop_len(l, (int)(bars * FC_BEATS_PER_BAR * 60.0f / bpm * sr));
    looper_set_layer(l, p->loop_layer);   /* Event Horizon drains this toward 0.08 via the macro lerp */
    granular_set_grain_size(g, p->grain_size);
    granular_set_scatter(g, p->scatter);
    granular_set_mod_depth(g, 0.0f);
    microloop_set_hold(m, p->micro_hold);
    { float mb = p->micro_bars > 0.01f ? p->micro_bars : 0.25f;      /* Satellite micro length */
      int mlen = (int)(mb * FC_BEATS_PER_BAR * 60.0f / bpm * sr); if (mlen < 1) mlen = 1;
      microloop_set_loop_len(m, mlen); }
    bloom_set_amount(b, p->bloom * 0.15f);
    drift_set_amount(d, p->drift_amt);
    harmony_set_amount(h, p->spectra);
    harmony_set_ring(h, p->ring);
    /* The chord itself (powf per voice) is rebuilt in fc_render_block only on a key/chord
     * change, not here — this runs on every param move (Flux, a Gravity ramp). */
    granular_set_mod_rate_hz(g, 0.05f * expf(p->mod_rate * 5.075f));   /* granular pitch-mod LFO rate */
}

/* Process ONE block of n (<= FC_BLK) frames. State persists in st across calls. */
static void fc_render_block(fc_state* st, looper_t* l, granular_t* g, microloop_t* m,
                            harmony_t* h, bloom_t* b, drift_t* d, const full_params* p, double sr,
                            const float* in_l, const float* in_r, float* out_l, float* out_r, int n) {
    if (n > FC_BLK) n = FC_BLK;
    const float kLoopBedMakeup = 1.9f;   /* plugin processBlock value */
    const float scatter  = p->scatter;
    const float cleanG   = (scatter <= 0.5f) ? 1.0f : (1.0f - 2.0f * (scatter - 0.5f));
    const float shimmerG = 0.55f + 0.30f * scatter;   /* grain floor so the pitched (oct/5th)
                                                         grains blend as an in-key bed */
    const float driftFbGain = 0.22f * p->drift_amt * (1.0f - 0.78f * p->decay) * (1.0f - 0.50f * p->spectra);
    /* Plugin one-pole cutoffs at the host rate: a 5 Hz DC blocker and a 2500 Hz low-pass
     * on the drift-regen feedback. The regen LP must stay this bright — a sub-bass cutoff
     * makes the Flux wash spiral DOWN in pitch (feeds back only lows). */
    const float dcIC = 1.0f - expf(-6.2831853f *    5.0f / (float) sr);
    const float fbIC = 1.0f - expf(-6.2831853f * 2500.0f / (float) sr);

    /* Re-push coefficients only when params change, and — because the macro ramps
     * (Gravity/Flux) change a param every 2 ms block for ~2 s — throttle continuous
     * changes to every 4th block (~8 ms; inaudible, and each module smooths its own
     * target per-sample). Key/chord changes are discrete, so they push immediately. */
#ifdef AMB_PROFILE
    unsigned int _tp = time_us();
#endif
    {
        int keyChord = !st->have_pushed || p->key != st->last_pushed.key || p->chord != st->last_pushed.chord;
        int changed  = !st->have_pushed || memcmp(p, &st->last_pushed, sizeof(full_params)) != 0;
        if (changed && (keyChord || (st->push_ctr & 3u) == 0u)) {
            fc_push_params(l, g, m, h, b, d, p, sr);
            if (keyChord) {
                float f[HARMONY_MAX_VOICES]; int nv = fc_build_chord(p->key, p->chord, f);
                harmony_set_chord(h, f, nv);
            }
            st->last_pushed = *p;
            st->have_pushed = 1;
        }
        st->push_ctr++;
    }
#ifdef AMB_PROFILE
    g_stage_us[6] += time_us() - _tp;   /* push (incl. its re-fire cost during a ramp) */
    unsigned int _tl = time_us();
    #define STG(k) do { unsigned int _tn = time_us(); g_stage_us[k] += _tn - _tl; _tl = _tn; } while (0)
#else
    #define STG(k)
#endif

    /* Event Horizon (horizon 1 = full sustain, lower = drain). The drain is done cheaply
     * by the macro lerp pulling the loop + micro feedback down (so the buffers decay) plus
     * the wet-tail duck below — not by scanning the whole loop buffer each block, which is
     * too expensive on the RP2350. */
    const float horizonClear = p->horizon >= 1.0f ? 0.0f : 1.0f - p->horizon;   /* 0..1 */

    for (int i = 0; i < n; i++) {                        /* DC block */
        st->dcL += dcIC * (in_l[i] - st->dcL); st->dcR += dcIC * (in_r[i] - st->dcR);
        st->dryL[i] = in_l[i] - st->dcL; st->dryR[i] = in_r[i] - st->dcR;
    }
    for (int i = 0; i < n; i++) { st->srcL[i] = st->dryL[i]; st->srcR[i] = st->dryR[i]; }
    if (driftFbGain > 0.0f || st->driftFbCur > 1e-6f)   /* drift regeneration */
        for (int i = 0; i < n; i++) {
            st->driftFbCur += 0.0007f * (driftFbGain - st->driftFbCur);
            float fl = (i < st->revFbN) ? st->revFbL[i] : 0.f, fr = (i < st->revFbN) ? st->revFbR[i] : 0.f;
            st->fbL += fbIC * (fl - st->fbL); st->fbR += fbIC * (fr - st->fbR);
            st->srcL[i] += st->driftFbCur * fast_tanhf(st->fbL); st->srcR[i] += st->driftFbCur * fast_tanhf(st->fbR);
        }

    looper_process(l, st->srcL, st->srcR, st->loopL, st->loopR, n);
    for (int i = 0; i < n; i++) { st->loopL[i] *= kLoopBedMakeup; st->loopR[i] *= kLoopBedMakeup; }
    STG(0);   /* looper + drift regen */

    granular_process(g, st->loopL, st->loopR, st->granL, st->granR, n);
    for (int i = 0; i < n; i++) { st->layL[i] = cleanG * st->loopL[i] + shimmerG * st->granL[i];
                                  st->layR[i] = cleanG * st->loopR[i] + shimmerG * st->granR[i]; }
    STG(1);   /* granular */

    bloom_process(b, st->srcL, st->srcR, st->blL, st->blR, n);

    microloop_process(m, st->blL, st->blR, st->micL, st->micR, n);
    /* Satellite makeup (plugin processBlock): the microloop's own out-gain is
     * 0.25*sqrt(hold), far quieter than the loop bed. Invert toward a flat ~1.1 low/mid
     * level (clamped 1..14), taper to unity approaching freeze, then a -25% trim. */
    { float mh = p->micro_hold < 0.f ? 0.f : (p->micro_hold > 1.f ? 1.f : p->micro_hold);
      float og = 0.25f * sqrtf(mh > 1.0e-4f ? mh : 1.0e-4f);
      float mk = 1.1f / og; if (mk < 1.f) mk = 1.f; else if (mk > 14.f) mk = 14.f;
      float tp = (mh - 0.7f) * (1.0f / 0.3f); if (tp < 0.f) tp = 0.f; else if (tp > 1.f) tp = 1.f;
      mk += (1.0f - mk) * tp; mk *= 0.75f;
      for (int i = 0; i < n; i++) { st->micL[i] *= mk; st->micR[i] *= mk; } }
    /* Micro reverb send: full for short/mid delays, reduced in the held-pad zone (plugin).
     * rin = bloom + layered + microRevSend*micro; the wet bus below uses the full micro. */
    { float mp = (p->micro_hold - 0.80f) * (1.0f / 0.15f); if (mp < 0.f) mp = 0.f; else if (mp > 1.f) mp = 1.f;
      float microRevSend = 1.0f - 0.45f * mp;
      for (int i = 0; i < n; i++) { st->rinL[i] = st->blL[i] + st->layL[i] + microRevSend * st->micL[i];
                                    st->rinR[i] = st->blR[i] + st->layR[i] + microRevSend * st->micR[i]; } }
    STG(2);   /* bloom + microloop + makeup */

    { float t = (p->decay - 0.30f) * (1.0f / 0.70f); if (t < 0.f) t = 0.f; else if (t > 1.f) t = 1.f;
      dattorro_set_decay(st->dat, t);                       /* Tail -> tail length (tracks the plugin) */
      dattorro_set_mod(st->dat, 0.25f + 0.75f * p->mod_depth); /* Flux + a floor so the tank always shimmers */
      dattorro_set_damp(st->dat, 0.22f); }                  /* bright, lush tail */
    dattorro_process(st->dat, st->rinL, st->rinR, st->wetL, st->wetR, n);
    STG(3);   /* reverb (Dattorro) */

    if (horizonClear > 0.001f) {                 /* Event Horizon ducks the reverb wash (1..0.15) */
        float wetTailGain = 1.0f - 0.85f * horizonClear;
        for (int i = 0; i < n; i++) { st->wetL[i] *= wetTailGain; st->wetR[i] *= wetTailGain; }
    }
    /* Drift regen taps the PRE-harmony wet (reverb wash only). The plugin taps post-harmony
     * so the chord recirculates, but the port's hotter Dattorro turns that into a tuned
     * runaway at the chord pitches (feedback that changes with the chord), so feed back only
     * the wash and let harmony sit on top. */
    for (int i = 0; i < n; i++) { st->revFbL[i] = st->wetL[i]; st->revFbR[i] = st->wetR[i]; } st->revFbN = n;
    harmony_process(h, st->wetL, st->wetR, st->wetL, st->wetR, n);          /* add the Spectra chord */
    for (int i = 0; i < n; i++) { st->wbL[i] = st->layL[i] + st->micL[i] + st->wetL[i];
                                  st->wbR[i] = st->layR[i] + st->micR[i] + st->wetR[i]; }
    STG(4);   /* harmony (Spectra) */
    drift_process(d, st->wbL, st->wbR, st->wbL, st->wbR, n);                /* wet-bus detune */

    /* Equal-power dry/wet crossfade (plugin): 50% keeps full loudness vs a linear blend's
     * -6 dB dip. Gains computed once per block — mix is already smoothed upstream, and
     * per-sample fast_cosf/sinf here would be over the core1 budget. */
    st->mixCur += 0.10f * (p->mix - st->mixCur);
    const float mmix = st->mixCur;
    const float dg = fast_cosf(mmix * 1.5707963f), wg = fast_sinf(mmix * 1.5707963f);
    /* Gravity: slow ~0.30 Hz tremolo throb (post-mix), per-sample only when engaged. */
    const float gravAmt   = p->gravity < 0.f ? 0.f : (p->gravity > 1.f ? 1.f : p->gravity);
    const float tremInc   = 6.2831853f * 0.30f / (float) sr;
    const float tremDepth = 0.40f * gravAmt;
    float gph = st->gravPhase;
    for (int i = 0; i < n; i++) {
        float lv = dg * st->dryL[i] + wg * st->wbL[i], rv = dg * st->dryR[i] + wg * st->wbR[i];
        if (gravAmt > 0.001f) {
            gph += tremInc; if (gph > 6.2831853f) gph -= 6.2831853f;
            float trem = 1.0f - tremDepth * (0.5f - 0.5f * fast_cosf(gph));
            lv *= trem; rv *= trem;
        }
#ifdef FC_SOFT_CLIP
        lv = fast_tanhf(lv); rv = fast_tanhf(rv);   /* soft-clip the hot poly bus; plugin hard-clips */
#else
        lv = lv < -1 ? -1 : lv > 1 ? 1 : lv; rv = rv < -1 ? -1 : rv > 1 ? 1 : rv;
#endif
        out_l[i] = lv; out_r[i] = rv;
    }
    st->gravPhase = gph;
    STG(5);   /* drift + mix/output */
#ifdef AMB_PROFILE
    g_stage_n++;
#endif
    #undef STG
}

/* Harness convenience: render `total` frames in FC_BLK chunks (one fc_state). */
static void fc_render(looper_t* l, granular_t* g, microloop_t* m,
                      harmony_t* h, bloom_t* b, drift_t* d, const full_params* p, double sr,
                      const float* in_l, const float* in_r, float* out_l, float* out_r, int total) {
    static fc_state st;                       /* static: keep ~22 KB off the stack */
    fc_init(&st, p->mix);
    if (!st.dat) st.dat = dattorro_create(sr);
    for (int start = 0; start < total; start += FC_BLK) {
        int n = (FC_BLK < total - start) ? FC_BLK : (total - start);
        fc_render_block(&st, l, g, m, h, b, d, p, sr, in_l + start, in_r + start, out_l + start, out_r + start, n);
    }
}
#endif
/* Rolling-capture stereo looper with feedback. */


/* Loop-bed storage type. Default float; build with -DLOOPER_I16 to store the
 * bed as int16 (Plinky-native): halves the PSRAM footprint and bytes/sample on
 * the slow bus. The loop is sequential-access so int16 adds no scatter penalty;
 * the feedback path picks up ~96 dB quantization noise, inaudible under the
 * soft-saturated ambient wash. ld()/st() are identity in the float build, so
 * that build is behaviourally unchanged. */
#ifdef LOOPER_I16
typedef int16_t lsamp_t;
static inline float   ld(lsamp_t v) { return (float)v * (1.0f / 32768.0f); }
static inline lsamp_t st(float v) {
    v = v > 1.0f ? 1.0f : (v < -1.0f ? -1.0f : v);
    /* round-to-nearest without lrintf (wasm toolchain doesn't provide it) */
    float s = v * 32767.0f;
    return (lsamp_t)(s < 0.0f ? s - 0.5f : s + 0.5f);
}
#else
typedef float lsamp_t;
static inline float   ld(lsamp_t v) { return v; }
static inline lsamp_t st(float v) { return v; }
#endif

struct looper_s {
    lsamp_t *buf_L;
    lsamp_t *buf_R;
    int    buf_capacity;   /* allocated size — sets the max loop length */
    int    loop_len;       /* active read offset; <= buf_capacity */
    int    write_pos;
    /* Smoothed feedback — abrupt knob changes would otherwise inject a
     * step into the buffer and echo forever. */
    float  fb_target;
    float  fb_current;

    /* Loop-length crossfade state (same pattern as microloop). MIDI-clock
     * follower can re-anchor loop_len every loop pass; crossfade hides
     * the resulting read-pointer jump. */
    int    loop_len_pending;
    int    loop_len_queued;
    int    has_queued;
    int    crossfade_remaining;

    /* Rate-scaled time constants (equal the references at 44.1 kHz). */
    float  smooth_c;
    int    crossfade_len;

    /* Dilate: reverse-delay read. Two backward heads offset by half the window,
     * Hann-crossfaded so there's no seam click and pitch is preserved. The OUTPUT
     * crossfades forward<->reverse by reverse_current; the feedback write stays
     * forward (the loop keeps evolving normally, we just play it back backward). */
    float  reverse_target, reverse_current;
    int    rev_counter;
    int    rev_base[2];
    int    reverse_was_active;  /* edge-detect reverse onset to re-anchor the read window */
};

#define LOOPER_SMOOTH_COEF   0.9989f  /* ~20 ms time constant @ 44.1 kHz */
#define LOOPER_CROSSFADE_LEN 512      /* ~11.6 ms linear crossfade */

/* Padé-3 tanh approximation — smooth soft-saturation for the feedback path.
 * Cheap (5 muls + 2 adds inside range) and bounded to ±1.0. Replaces hard
 * clip which produced clicky edges when sustained input + fb=1 saturated
 * the buffer. */
static inline float soft_sat(float x) {
    if (x >  3.0f) return  1.0f;
    if (x < -3.0f) return -1.0f;
    float x2 = x * x;
    return x * (27.0f + x2) / (27.0f + 9.0f * x2);
}

looper_t* looper_create(int buf_capacity_samples, double sample_rate) {
    const double sr = sample_rate > 0.0 ? sample_rate : AMB_REF_SAMPLE_RATE;
    if (buf_capacity_samples <= 0) return NULL;
    looper_t *l = (looper_t*)calloc(1, sizeof(looper_t));
    if (!l) return NULL;
    l->smooth_c      = amb_scale_onepole(LOOPER_SMOOTH_COEF, sr);
    l->crossfade_len = amb_scale_samples(LOOPER_CROSSFADE_LEN, sr);
    l->buf_capacity = buf_capacity_samples;
    l->loop_len = buf_capacity_samples;   /* default: full capacity */
    l->buf_L = (lsamp_t*)calloc((size_t)buf_capacity_samples, sizeof(lsamp_t));
    l->buf_R = (lsamp_t*)calloc((size_t)buf_capacity_samples, sizeof(lsamp_t));
    if (!l->buf_L || !l->buf_R) { looper_destroy(l); return NULL; }
    return l;
}

void looper_set_loop_len(looper_t *l, int loop_len_samples) {
    if (!l) return;
    if (loop_len_samples < 1) loop_len_samples = 1;
    if (loop_len_samples > l->buf_capacity) loop_len_samples = l->buf_capacity;

    /* If a crossfade is already running, queue the new value — don't
     * disrupt the in-flight transition. */
    if (l->crossfade_remaining > 0) {
        if (loop_len_samples != l->loop_len_pending) {
            l->loop_len_queued = loop_len_samples;
            l->has_queued = 1;
        }
        return;
    }
    if (loop_len_samples != l->loop_len) {
        l->loop_len_pending = loop_len_samples;
        l->crossfade_remaining = l->crossfade_len;
    }
}

void looper_destroy(looper_t *l) {
    if (!l) return;
    free(l->buf_L);
    free(l->buf_R);
    free(l);
}

/* Clear the captured loop + feedback state (RT-safe: no alloc). Keeps params. */
void looper_reset(looper_t *l) {
    if (!l) return;
    memset(l->buf_L, 0, (size_t)l->buf_capacity * sizeof(lsamp_t));
    memset(l->buf_R, 0, (size_t)l->buf_capacity * sizeof(lsamp_t));
    l->write_pos = 0;
    l->fb_current = 0.0f;
    l->crossfade_remaining = 0;
    l->has_queued = 0;
    l->reverse_current = 0.0f;
    l->rev_counter = 0;
    l->reverse_was_active = 0;
}

/* Dilate: 0 = forward output, 1 = reversed (reverse-delay read). Smoothed in
 * process so toggling doesn't click. The feedback path stays forward. */
void looper_set_reverse(looper_t *l, float amount_0_1) {
    if (!l) return;
    if (amount_0_1 < 0.0f) amount_0_1 = 0.0f;
    if (amount_0_1 > 1.0f) amount_0_1 = 1.0f;
    l->reverse_target = amount_0_1;
}

/* Event Horizon: scale the active loop window (the last loop_len samples ending
 * at write_pos) by `factor` once per block — actively decays the captured loop so
 * lowering Horizon empties the buffer over time (a global "let-go"/feedback pull),
 * not just ducks the output. factor >= 1 is a no-op. RT-safe (no alloc). */
void looper_leak(looper_t *l, float factor) {
    if (!l || factor >= 0.99999f) return;
    if (factor < 0.0f) factor = 0.0f;
    const int cap = l->buf_capacity;
    int len = l->loop_len; if (len > cap) len = cap;
    int idx = l->write_pos;
    for (int i = 0; i < len; i++) {
        if (--idx < 0) idx += cap;
        l->buf_L[idx] = st(ld(l->buf_L[idx]) * factor);
        l->buf_R[idx] = st(ld(l->buf_R[idx]) * factor);
    }
}

void looper_set_layer(looper_t *l, float layer_0_1) {
    if (!l) return;
    if (layer_0_1 < 0.0f) layer_0_1 = 0.0f;
    if (layer_0_1 > 1.0f) layer_0_1 = 1.0f;
    /* knob^2 curve for perceptual feel — soft start, lush mid, very long top.
     * Capped below unity so the looper never fully freezes (fb=1 -> (1-fb)=0
     * stops capturing input): at 100% it's a long-sustain loop that still
     * takes new input. Soft-clip in process() guards against runaway. */
    float fb = layer_0_1 * layer_0_1;
    if (fb > 0.97f) fb = 0.97f;
    l->fb_target = fb;
}

void looper_clear(looper_t *l) {
    if (!l) return;
    memset(l->buf_L, 0, (size_t)l->buf_capacity * sizeof(lsamp_t));
    memset(l->buf_R, 0, (size_t)l->buf_capacity * sizeof(lsamp_t));
}

void looper_process(looper_t *l,
                    const float *in_l, const float *in_r,
                    float *out_l, float *out_r,
                    int frames) {
    if (!l || frames <= 0) return;
    int pos = l->write_pos;
    const int cap = l->buf_capacity;

    float fb_curr      = l->fb_current;
    const float fb_t   = l->fb_target;
    const float c      = l->smooth_c;
    const float ic     = 1.0f - c;

    for (int n = 0; n < frames; n++) {
        fb_curr = c * fb_curr + ic * fb_t;

        /* Read from active loop_len position. */
        int read_pos_a = pos - l->loop_len;
        if (read_pos_a < 0) read_pos_a += cap;
        float loopL = ld(l->buf_L[read_pos_a]);
        float loopR = ld(l->buf_R[read_pos_a]);

        /* During crossfade, blend with read at the pending loop_len.
         * Linear (gain-equal) crossfade — the two read positions are highly
         * correlated (same buffer, shifted by a few samples) so equal-power
         * cosine/sine causes a 3 dB hump mid-fade. Linear stays flat. */
        if (l->crossfade_remaining > 0) {
            int read_pos_b = pos - l->loop_len_pending;
            if (read_pos_b < 0) read_pos_b += cap;
            float loopL_b = ld(l->buf_L[read_pos_b]);
            float loopR_b = ld(l->buf_R[read_pos_b]);

            float gain_b = (float)(l->crossfade_len - l->crossfade_remaining) *
                           (1.0f / (float)l->crossfade_len);
            float gain_a = 1.0f - gain_b;
            loopL = gain_a * loopL + gain_b * loopL_b;
            loopR = gain_a * loopR + gain_b * loopR_b;

            l->crossfade_remaining--;
            if (l->crossfade_remaining == 0) {
                l->loop_len = l->loop_len_pending;
                if (l->has_queued && l->loop_len_queued != l->loop_len) {
                    l->loop_len_pending = l->loop_len_queued;
                    l->crossfade_remaining = l->crossfade_len;
                }
                l->has_queued = 0;
            }
        }

        /* Write input + feedback back into the buffer at write_pos.
         * Normalized feedback formula: buf = (1-fb)*in + fb*old. At steady
         * state buffer content converges to input level — no buildup, no
         * runaway. At fb=1.0 the input term goes to zero, naturally freezing
         * the buffer (true looper). soft_sat kept as safety against
         * transient peaks. */
        float in_g = 1.0f - fb_curr;
        l->buf_L[pos] = st(soft_sat(in_g * in_l[n] + fb_curr * loopL));
        l->buf_R[pos] = st(soft_sat(in_g * in_r[n] + fb_curr * loopR));

        /* Output: ONLY the loop signal (no dry). Caller mixes dry separately.
         * Makeup gain: the normalized (1-fb) capture + soft-clip leaves the loop
         * a bit under the dry level at high feedback; lift it so Layer ~100%
         * sits about equal to the dry signal (measured ~0.62x without this). */
        const float mk = 1.0f + 0.6f * fb_curr;

        /* Dilate: crossfade the OUTPUT to a reverse-delay read of the same buffer
         * (two backward heads offset by half the window, Hann-crossfaded → no seam,
         * pitch preserved). Forward feedback above is untouched. */
        float outLoopL = loopL, outLoopR = loopR;
        l->reverse_current = c * l->reverse_current + ic * l->reverse_target;
        const int rev_active = l->reverse_current > 0.0005f;
        /* On reverse ONSET, re-anchor the backward read window to "now". rev_counter
         * free-runs even while reverse is off, so without this the heads would read
         * from a stale anchor at non-zero Hann gain for up to one loop — the seam
         * masking that keeps steady-state reverse clickless doesn't cover turn-on
         * (an audible click when Dilate engages over a loud loop). Start head 0 at
         * phase 0 (gain 0) and both anchors at the write head so the first reads are
         * valid recent audio, blended in smoothly by the reverse_current ramp. */
        if (rev_active && !l->reverse_was_active) {
            l->rev_counter = 0;
            l->rev_base[0] = pos;
            l->rev_base[1] = pos;
        }
        l->reverse_was_active = rev_active;
        if (rev_active) {
            int L = l->loop_len; if (L < 2) L = 2;
            float rL = 0.0f, rR = 0.0f;
            for (int h = 0; h < 2; h++) {
                int ph = l->rev_counter + (h ? L / 2 : 0);
                while (ph >= L) ph -= L;
                if (ph == 0) l->rev_base[h] = pos;          /* anchor window start at "now" */
                int rabs = l->rev_base[h] - ph;             /* read backward from the anchor */
                while (rabs < 0) rabs += cap;
                const float gain = 0.5f - 0.5f * fast_cosf(6.2831853f * (float)ph / (float)L);
                rL += gain * ld(l->buf_L[rabs]);
                rR += gain * ld(l->buf_R[rabs]);
            }
            const float rc = l->reverse_current;
            outLoopL = (1.0f - rc) * loopL + rc * rL;
            outLoopR = (1.0f - rc) * loopR + rc * rR;
        }
        { int Lw = l->loop_len < 2 ? 2 : l->loop_len;
          l->rev_counter++; if (l->rev_counter >= Lw) l->rev_counter = 0; }

        out_l[n] = fb_curr * outLoopL * mk;
        out_r[n] = fb_curr * outLoopR * mk;

        pos++; if (pos >= cap) pos = 0;
    }
    l->write_pos = pos;
    l->fb_current = fb_curr;
}
/* Granular stage — 8-grain scheduler over a 2s capture ring. */


#ifndef M_PI
#define M_PI 3.14159265358979323846
#endif
#define TWO_PI (2.0f * (float)M_PI)

#define G_SAMPLE_RATE       44100
/* 5 s capture ring. Must exceed 2*grain_max + max_scatter so a REVERSED grain
 * (reads backward `len` while write advances `len` = 2*len of travel, plus the
 * scatter offset) cannot lap the ring and meet the write head mid-grain — that
 * crossing reads a full-buffer content jump at high envelope gain (an audible
 * click). 2*1.5s + 1s = 4s of travel, so 5s leaves margin. */
#define G_BUF_SAMPLES       (5 * G_SAMPLE_RATE)       /* 5 s stereo capture */
#define G_MAX_SCATTER_SAMP  G_SAMPLE_RATE             /* 1 s max scatter offset into the past */
#ifndef G_MAX_GRAINS
#define G_MAX_GRAINS        3     /* Granular is the heaviest core1 stage — each grain is a
                                     scattered PSRAM read stream, and the RP2350's small XIP
                                     cache thrashes on more than a few. 3 fits the ~2 ms budget
                                     with Gravity up + a synth voice. */
#endif
#define G_GRAIN_MIN_SAMPLES 4410                  /* 100 ms — long, smooth grains */
#define G_GRAIN_MAX_SAMPLES 66150                 /* 1.5 s — stretched pad grains */

/* Pitch quantization set — universally consonant intervals.
 * Octaves and perfect fifths are tonally neutral (work in major, minor,
 * modal, drone). Avoiding thirds/sixths keeps Ambiotica from accidentally
 * imposing a key on the source material. */
static const float G_PITCH_STEPS[5] = {
    1.0f,                  /* unison */
    2.0f,                  /* +1 octave */
    0.5f,                  /* −1 octave */
    1.4983070768766815f,   /* +P5  (2^(+7/12)) */
    0.6674199270738774f    /* −P5  (2^(−7/12)) */
};

typedef struct {
    int   active;
    float read_pos;       /* fractional position in buffer (L & R share) */
    float read_step;      /* per-sample increment = pitch ratio (negative = reversed) */
    int   age;            /* samples since spawn */
    int   length;         /* total samples in this grain */
    float inv_length;     /* 1/length — precomputed so the window is a LUT read, not a divide */
    int   reversed;       /* Dilate: 1 = backward read + reverse-swell envelope */
} grain_t;

/* Hann window LUT: the forward grain envelope 0.5*(1-cos(2*pi*phase)) is read from a
 * table instead of a per-grain per-sample fast_cosf. Exact Hann (more accurate than
 * the trig approximation), and it reaches 0 at both edges so grains never click. */
#define G_HANN_N 2048
static float g_hann_lut[G_HANN_N + 1];
static int   g_hann_ready = 0;
static void g_hann_init(void) {
    if (g_hann_ready) return;
    for (int i = 0; i <= G_HANN_N; i++)
        g_hann_lut[i] = 0.5f * (1.0f - cosf(TWO_PI * (float)i / (float)G_HANN_N));
    g_hann_ready = 1;
}

/* Capture ring stored as INTERLEAVED int16 [L,R,L,R,...]: halves the PSRAM data vs
 * float and puts each frame's L+R in one cache line, so a grain read touches one
 * cache line instead of two separate arrays — cuts the PSRAM thrashing that made
 * granular the heaviest core1 stage. Quantization is inaudible under a grain cloud. */
static inline float   g_ld(short v) { return (float)v * (1.0f / 32768.0f); }
static inline short   g_st(float v) { v = v > 1.f ? 1.f : (v < -1.f ? -1.f : v);
                                      float s = v * 32767.f; return (short)(s < 0.f ? s - 0.5f : s + 0.5f); }

struct granular_s {
    short *buf;            /* interleaved int16 stereo: buf[pos*2]=L, buf[pos*2+1]=R */
    int    buf_len;
    int    write_pos;

    grain_t grains[G_MAX_GRAINS];
    int     samples_to_next;     /* countdown to next grain spawn */
    unsigned spawn_count;        /* monotonic # of grains spawned (GUI tap, read-only) */

    /* Rate-scaled grain-length bounds (equal G_GRAIN_*_SAMPLES at 44.1 kHz). */
    int     grain_min;
    int     grain_max;
    int     max_scatter;   /* rate-scaled (1 s @44.1k) — decoupled from buf_len */

    /* Params */
    float grain_size_0_1;
    float scatter_0_1;
    float reverse_0_1;       /* "Dilate": fraction of grains that play backward */

    /* LFO modulation — wobbles each active grain's pitch in sync with
     * reverb's mod, giving coherent breathing across both stages. */
    lfo_t mod_lfo;
    float mod_depth_cents;   /* 0..100 cents (1 semitone) at full depth */

    /* LCG RNG */
    uint32_t rng;
};

static inline uint32_t lcg_next(uint32_t *s) {
    *s = (*s) * 1103515245u + 12345u;
    return *s;
}
/* Uniform float in [-1, +1]. */
static inline float lcg_bipolar(uint32_t *s) {
    uint32_t v = lcg_next(s);
    return (float)v * (2.0f / 4294967295.0f) - 1.0f;
}
/* Uniform float in [0, 1). */
static inline float lcg_unipolar(uint32_t *s) {
    uint32_t v = lcg_next(s);
    return (float)v * (1.0f / 4294967295.0f);
}

static int current_grain_length(const granular_t *g) {
    int span = g->grain_max - g->grain_min;
    return g->grain_min + (int)((float)span * g->grain_size_0_1);
}

static void spawn_grain(granular_t *g) {
    /* Find a free slot — drop the spawn if none free. */
    grain_t *gr = NULL;
    for (int i = 0; i < G_MAX_GRAINS; i++) {
        if (!g->grains[i].active) { gr = &g->grains[i]; break; }
    }
    if (!gr) return;

    int len = current_grain_length(g);
    gr->length = len;
    gr->inv_length = len > 0 ? 1.0f / (float)len : 1.0f;
    gr->age = 0;

    /* Pitch — quantize to unison / ±octave / ±fifth (G_PITCH_STEPS).
     * Scatter controls probability of leaving unison; when it does, the
     * non-unison interval is picked uniformly from the four others.
     *   scatter=0   → 100% unison
     *   scatter=0.5 → 60% unison, 10% each non-unison
     *   scatter=1   → 20% each (all 5 intervals equally likely) */
    float pick = lcg_unipolar(&g->rng);
    float p_unity = 1.0f - g->scatter_0_1 * 0.8f;
    int   idx;
    if (pick < p_unity) {
        idx = 0;  /* unison */
    } else {
        float pick2 = lcg_unipolar(&g->rng);
        int j = (int)(pick2 * 4.0f);
        if (j >= 4) j = 3;
        idx = j + 1;  /* 1..4 → ±oct, ±P5 */
    }
    gr->read_step = G_PITCH_STEPS[idx];

    /* Start position — read from `len` samples behind write_pos so the
     * grain stays in valid past audio for its full duration (even at +1 oct
     * pitch the read just catches up to write at grain end). Scatter then
     * offsets the start by up to max_scatter (1 s) FURTHER INTO THE PAST.
     *
     * The offset must be into the past only (|scatter_off|): a negative offset
     * would place the read window ahead of / less than `len` behind the write
     * head, so the forward read crosses the write seam mid-grain and reads a
     * full-buffer content jump at high envelope gain (an audible click). This is
     * the same guard the reversed path applies below (see rev_scatter). */
    int latency = len;
    int max_scatter = g->max_scatter;
    int scatter_off = (int)((float)max_scatter * g->scatter_0_1 * lcg_bipolar(&g->rng));
    if (scatter_off < 0) scatter_off = -scatter_off;
    int start = g->write_pos - latency - scatter_off;
    /* Bring into [0, buf_len). */
    while (start < 0)            start += g->buf_len;
    while (start >= g->buf_len)  start -= g->buf_len;

    /* Dilate: this grain plays BACKWARD. Forced to UNISON (read_step -1) so the
     * reversed read stays in tune — the ±oct/±5th pitch scatter on a backward read
     * is what sounds out of key. Reads the last `len` samples from their end back
     * to the start (a clean, valid past-audio window). Probability = reverse_0_1,
     * so a bool toggle (0/1) flips the whole cloud. The reverse-swell envelope is
     * applied in process() (see gr->reversed). */
    if (g->reverse_0_1 > 0.0f && lcg_unipolar(&g->rng) < g->reverse_0_1) {
        gr->reversed = 1;
        gr->read_step = -1.0f;                          // unison, backward
        /* The backward read begins at the window END and moves AWAY from the
         * advancing write head — but ONLY if the window sits behind write. A
         * negative scatter would put the end ahead of write, so the backward read
         * would cross the write head mid-grain (reading a buffer-sized content jump
         * at high envelope gain → a click). Force the scatter into the past so the
         * whole reversed window stays behind write. With the 5 s ring (see
         * G_BUF_SAMPLES) this guarantees 2*len + scatter < buf_len, so the read
         * also can't lap the ring back into the write head. */
        int rev_scatter = scatter_off < 0 ? -scatter_off : scatter_off;
        int rstart = g->write_pos - latency - rev_scatter;
        while (rstart < 0)           rstart += g->buf_len;
        while (rstart >= g->buf_len) rstart -= g->buf_len;
        float endp = (float)rstart + (float)len;        // = write_pos - rev_scatter <= write_pos
        while (endp >= (float)g->buf_len) endp -= (float)g->buf_len;
        gr->read_pos = endp;
    } else {
        gr->reversed = 0;
        gr->read_pos = (float)start;
    }

    gr->active = 1;
    g->spawn_count++;            /* GUI tap: one real grain onset */
}

unsigned granular_grain_spawns(const granular_t *g) {
    return g ? g->spawn_count : 0u;
}

granular_t* granular_create(double sample_rate) {
    const double sr = sample_rate > 0.0 ? sample_rate : AMB_REF_SAMPLE_RATE;
    granular_t *g = (granular_t*)calloc(1, sizeof(granular_t));
    if (!g) return NULL;
    g_hann_init();
    /* 5 s capture ring + grain bounds scaled to the host rate. */
    g->buf_len     = amb_scale_samples(G_BUF_SAMPLES, sr);
    g->grain_min   = amb_scale_samples(G_GRAIN_MIN_SAMPLES, sr);
    g->grain_max   = amb_scale_samples(G_GRAIN_MAX_SAMPLES, sr);
    g->max_scatter = amb_scale_samples(G_MAX_SCATTER_SAMP, sr);
    g->buf = (short*)calloc((size_t)g->buf_len * 2, sizeof(short));
    if (!g->buf) { granular_destroy(g); return NULL; }
    g->grain_size_0_1 = 0.5f;
    g->scatter_0_1 = 0.0f;
    lfo_init(&g->mod_lfo, (int)sr);
    lfo_set_rate_hz(&g->mod_lfo, 0.3f);
    g->mod_depth_cents = 0.0f;
    g->rng = 0x12345678u;
    g->samples_to_next = current_grain_length(g) / 2;   /* 2x = Hann COLA (constant amp, one fewer PSRAM read stream) */
    return g;
}

void granular_destroy(granular_t *g) {
    if (!g) return;
    free(g->buf);
    free(g);
}

/* Clear the capture ring + kill active grains (RT-safe). Keeps params. */
void granular_reset(granular_t *g) {
    if (!g) return;
    memset(g->buf, 0, (size_t)g->buf_len * 2 * sizeof(short));
    g->write_pos = 0;
    g->samples_to_next = 0;
    for (int i = 0; i < G_MAX_GRAINS; i++) g->grains[i].active = 0;
}

void granular_set_grain_size(granular_t *g, float size_0_1) {
    if (!g) return;
    if (size_0_1 < 0.0f) size_0_1 = 0.0f;
    if (size_0_1 > 1.0f) size_0_1 = 1.0f;
    g->grain_size_0_1 = size_0_1;
}

void granular_set_scatter(granular_t *g, float scatter_0_1) {
    if (!g) return;
    if (scatter_0_1 < 0.0f) scatter_0_1 = 0.0f;
    if (scatter_0_1 > 1.0f) scatter_0_1 = 1.0f;
    g->scatter_0_1 = scatter_0_1;
}

/* Dilate: 0 = all grains forward, 1 = all reversed (a fraction reverses that
 * proportion). Decided per grain at spawn; existing grains finish their life, so
 * toggling crossfades over ~a grain length. */
void granular_set_reverse(granular_t *g, float amount_0_1) {
    if (!g) return;
    if (amount_0_1 < 0.0f) amount_0_1 = 0.0f;
    if (amount_0_1 > 1.0f) amount_0_1 = 1.0f;
    g->reverse_0_1 = amount_0_1;
}

void granular_set_mod_depth(granular_t *g, float depth_0_1) {
    if (!g) return;
    if (depth_0_1 < 0.0f) depth_0_1 = 0.0f;
    if (depth_0_1 > 1.0f) depth_0_1 = 1.0f;
    g->mod_depth_cents = depth_0_1 * 100.0f;
}

void granular_set_mod_rate_hz(granular_t *g, float hz) {
    if (!g) return;
    if (hz < 0.0f) hz = 0.0f;
    lfo_set_rate_hz(&g->mod_lfo, hz);
}

void granular_process(granular_t *g,
                      const float *in_l, const float *in_r,
                      float *out_l, float *out_r,
                      int frames) {
    if (!g || frames <= 0) return;

    const int buf_len = g->buf_len;
    const float mod_cents = g->mod_depth_cents;

    for (int n = 0; n < frames; n++) {
        /* Per-sample shared mod factor (same across all active grains). */
        float lfo_val = lfo_tick_sine(&g->mod_lfo);
        float pitch_mod = (mod_cents > 0.0f)
            ? fast_exp2f(lfo_val * mod_cents * (1.0f / 1200.0f))
            : 1.0f;
        /* 1. Write current input to capture buffer. */
        g->buf[g->write_pos * 2]     = g_st(in_l[n]);
        g->buf[g->write_pos * 2 + 1] = g_st(in_r[n]);
        g->write_pos++;
        if (g->write_pos >= buf_len) g->write_pos = 0;

        /* 2. Grain scheduler — fire every length/2 samples (50% overlap). */
        g->samples_to_next--;
        if (g->samples_to_next <= 0) {
            spawn_grain(g);
            g->samples_to_next = current_grain_length(g) / 2;   /* 2x = Hann COLA (constant amp, one fewer PSRAM read stream) */
            if (g->samples_to_next < 1) g->samples_to_next = 1;
        }

        /* 3. Render active grains. */
        float sum_l = 0.0f, sum_r = 0.0f;
        for (int i = 0; i < G_MAX_GRAINS; i++) {
            grain_t *gr = &g->grains[i];
            if (!gr->active) continue;

            /* Linear-interp read at fractional position. */
            int pi = (int)gr->read_pos;
            float pf = gr->read_pos - (float)pi;
            int pi2 = pi + 1; if (pi2 >= buf_len) pi2 = 0;
            float yl = g_ld(g->buf[pi * 2])     * (1.0f - pf) + g_ld(g->buf[pi2 * 2])     * pf;
            float yr = g_ld(g->buf[pi * 2 + 1]) * (1.0f - pf) + g_ld(g->buf[pi2 * 2 + 1]) * pf;

            /* Envelope. Forward: Hann (smooth, overlap-adds to ~1.0). Reversed
             * (Dilate): a SWELL — amplitude rises across the grain then a quick
             * fade at the end, so it audibly blooms backward instead of just a
             * time-reversed Hann (which sounds barely reversed). */
            float phase = (float)gr->age * gr->inv_length;
            float env;
            if (gr->reversed) {
                env = (phase < 0.85f) ? fast_sinf(1.5707963f * (phase / 0.85f))
                                      : fast_cosf(1.5707963f * ((phase - 0.85f) / 0.15f));
                if (env < 0.f) env = 0.f;   /* fast-trig can dip <0 at grain edges -> click */
            } else {
                /* Forward Hann from the LUT — no per-grain fast_cosf, exact 0 at edges. */
                int hi = (int)(phase * (float)G_HANN_N);
                if (hi < 0) hi = 0; else if (hi > G_HANN_N) hi = G_HANN_N;
                env = g_hann_lut[hi];
            }

            sum_l += yl * env;
            sum_r += yr * env;

            /* Advance grain with shared LFO pitch wobble applied. */
            gr->read_pos += gr->read_step * pitch_mod;
            if (gr->read_pos >= (float)buf_len) gr->read_pos -= (float)buf_len;
            else if (gr->read_pos < 0.0f) gr->read_pos += (float)buf_len;
            gr->age++;
            if (gr->age >= gr->length) gr->active = 0;
        }

        out_l[n] = sum_l;
        out_r[n] = sum_r;
    }
}
/* Micro-loop — short feedback delay that locks into freeze near max hold. */


/* The octave shimmer and the freeze granular cloud are compiled out on this target:
 * both random-access their buffers, so on the RP2350 they are dominated by scattered-
 * PSRAM cache-miss latency, and both are inaudible under the reverb wash. The code is
 * kept behind these guards for reference / a future cache-friendly freeze — comment a
 * line to re-enable that piece. */
#define AMB_NO_SHIMMER
#define AMB_NO_CLOUD

#define M_SAMPLE_RATE       44100
#define M_MIN_LEN_SAMPLES   4410     /* 100 ms @ 44.1 kHz — above phasing range */
#define M_MAX_LEN_SAMPLES   264600   /* 6 s @ 44.1 kHz — fits 2 bars down to 80 BPM */
#define M_AUTO_FREEZE       0.95f    /* knob threshold for auto-engaged freeze */
#define M_SMOOTH_COEF       0.9989f  /* ~20 ms — for fb / out_gain */
#define M_CROSSFADE_LEN     2048     /* ~46 ms — equal-power crossfade between
                                         old and new read positions when loop_len
                                         changes. No pitch glide, no click. */
#define M_GRAINS            8        /* voices in the freeze drone cloud       */
#define M_FREEZE_MIX_T      0.050f   /* ~50 ms ramp of cloud in/out on freeze  */
#define M_CLOUD_GAIN        0.90f    /* level trim for the overlapped cloud    */

static inline float m_ld(short v) { return (float)v * (1.0f / 32768.0f); }
static inline short m_st(float v) { v = v > 1.f ? 1.f : (v < -1.f ? -1.f : v);
                                    float s = v * 32767.f; return (short)(s < 0.f ? s - 0.5f : s + 0.5f); }

struct microloop_s {
    short *buf;            /* interleaved int16 stereo capture: buf[pos*2]=L, [pos*2+1]=R
                              (halves PSRAM data + one cache line per frame vs buf_L/buf_R) */
    int    buf_capacity;
    int    write_pos;
    float  hold;       /* 0..1 — both loop length and blend amount */

    /* Rate-scaled time constants (equal the M_* references at 44.1 kHz). */
    int    min_len;
    int    max_len;
    int    crossfade_len;
    float  smooth_c;

    /* Smoothed gains. */
    float  fb_target,       fb_current;
    float  out_gain_target, out_gain_current;

    /* Loop length (read offset, samples). The host drives a continuous tempo-
     * relative target; a length change RE-ANCHORS via an equal-power crossfade
     * between the old and new FIXED read taps — the read pointer never sweeps,
     * so there is no pitch glide (and no click). Same approach as the looper.
     * Equal-power (not linear) because the two taps read decorrelated content
     * at different delays. Changes mid-fade queue, like the looper. */
    int    loop_len_current;     /* active read offset (also the cloud region) */
    int    loop_len_pending;     /* new offset being crossfaded in             */
    int    loop_len_queued;      /* a change requested mid-crossfade           */
    int    has_queued;           /* 1 if loop_len_queued is waiting            */
    int    xfade_remaining;      /* samples left in the active fade (0 = none) */

    /* Dilate: reverse-delay read (two backward heads offset by half the window,
     * Hann-crossfaded). The base delay read crossfades forward<->reverse by
     * reverse_current; the feedback write stays forward. */
    float  reverse_target, reverse_current;
    int    rev_counter;
    int    rev_base[2];

    /* Octave-up shimmer on the held pad (glassy/crystalline). */
    float *shbuf; int shlen, shwidx; float shphase;
    float  shimmer_amt;          /* ramps in as hold approaches freeze */
    float  lp_L, lp_R, lp_a1;    /* held-pad smoothing low-pass (blended by hold) */

    /* Seamless freeze drone: a granular cloud over the frozen buffer so the
     * held sound has no loop seam. Crossfaded in by freeze_mix while frozen. */
    double sr;
    float  freeze_mix;           /* 0..1: linear-loop read → grain cloud */
    float  freeze_mix_a;         /* per-sample ramp coef for freeze_mix  */
    unsigned rng;                /* LCG state for grain randomisation    */
    int    spawn_timer;          /* samples until the next grain spawns  */
    int    cloud_tick;           /* half-rate toggle: cloud recomputes every other sample */
    float  cloud_l, cloud_r;     /* held cloud output between half-rate computes */
    struct {
        float rd;                /* fractional read cursor into buf      */
        int   len, age, active;  /* grain length / progress / live flag  */
        float gL, gR;            /* per-grain stereo pan gains           */
    } grain[M_GRAINS];
};

/* Cheap LCG → [0,1). Deterministic (no Math.random), fine for grain spread. */
static inline float micro_rng01(microloop_t *m) {
    m->rng = m->rng * 1664525u + 1013904223u;
    return (float)(m->rng >> 8) * (1.0f / 16777216.0f);
}

/* Spawn one grain into a free voice, reading from a random spot within the
 * frozen region and playing forward so it always stays inside captured audio. */
static void micro_spawn_grain(microloop_t *m, int write_pos) {
    int gi = -1;
    for (int i = 0; i < M_GRAINS; i++) if (!m->grain[i].active) { gi = i; break; }
    if (gi < 0) return;                       /* all busy — skip this spawn */

    int region = m->loop_len_current;
    if (region < m->min_len) region = m->min_len;

    int len = (int)((0.15f + 0.25f * micro_rng01(m)) * (float)m->sr);  /* 0.15..0.40 s */
    int minoff = len + 64;
    if (minoff > region) { len = region - 64; if (len < 256) len = 256; minoff = len + 64; }
    int maxoff = region; if (maxoff < minoff) maxoff = minoff;
    int off = minoff + (int)((float)(maxoff - minoff) * micro_rng01(m));

    int cap = m->buf_capacity;
    int start = write_pos - off; while (start < 0) start += cap;
    float theta = (0.30f + 0.40f * micro_rng01(m)) * 1.5707963f;   /* keep both chans */

    m->grain[gi].rd = (float)start;
    m->grain[gi].len = len;
    m->grain[gi].age = 0;
    m->grain[gi].active = 1;
    m->grain[gi].gL = fast_cosf(theta);
    m->grain[gi].gR = fast_sinf(theta);

    /* Schedule next spawn so ~2 grains overlap: Hann at 50% overlap is COLA (constant
     * amplitude, no ripple) and drops a whole scattered-PSRAM read stream vs 3x — the
     * same cache win as the main granular. */
    m->spawn_timer = len / 2; if (m->spawn_timer < 1) m->spawn_timer = 1;
}

/* Advance + sum the grain cloud for one sample. `active` keeps spawning new
 * Hann-windowed grains; their faded edges hide the loop seam. */
static inline void micro_cloud(microloop_t *m, int active, int write_pos, int step,
                               float *out_l, float *out_r) {
    if (active) { m->spawn_timer -= step; if (m->spawn_timer <= 0) micro_spawn_grain(m, write_pos); }

    int cap = m->buf_capacity;
    float cl = 0.0f, cr = 0.0f;
    for (int gi = 0; gi < M_GRAINS; gi++) {
        if (!m->grain[gi].active) continue;
        int i0 = (int)m->grain[gi].rd; float fr = m->grain[gi].rd - (float)i0;
        int i1 = i0 + 1; if (i1 >= cap) i1 = 0;
        float bl0 = m_ld(m->buf[i0*2]),   bl1 = m_ld(m->buf[i1*2]);
        float br0 = m_ld(m->buf[i0*2+1]), br1 = m_ld(m->buf[i1*2+1]);
        float sL = bl0 + (bl1 - bl0) * fr;
        float sR = br0 + (br1 - br0) * fr;
        /* Hann window over the grain's life. */
        float w = 0.5f - 0.5f * fast_cosf(6.2831853f * ((float)m->grain[gi].age + 0.5f)
                                     / (float)m->grain[gi].len);
        cl += sL * w * m->grain[gi].gL;
        cr += sR * w * m->grain[gi].gR;
        m->grain[gi].rd += (float)step; if (m->grain[gi].rd >= (float)cap) m->grain[gi].rd -= (float)cap;
        m->grain[gi].age += step; if (m->grain[gi].age >= m->grain[gi].len) m->grain[gi].active = 0;
    }
    *out_l = cl * M_CLOUD_GAIN;
    *out_r = cr * M_CLOUD_GAIN;
}

/* Octave-up pitch shifter: two read heads, sin²/cos² crossfaded. */
static inline float micro_shimmer (microloop_t *m, float in) {
    m->shbuf[m->shwidx] = in;
    m->shphase -= 1.0f; if (m->shphase < 0.0f) m->shphase += (float)m->shlen;
    const float L = (float)m->shlen;
    const float x0 = m->shphase / L;
    float p1 = m->shphase + L * 0.5f; if (p1 >= L) p1 -= L;
    float s0, s1;
    /* i is already in [0,shlen) after the while, so i%shlen==i and (i-1) only needs a
     * single wrap — the modulo (integer divide, ~12 cyc each, 4x/sample) was dead cost. */
    { int bk=(int)m->shphase; float fr=m->shphase-(float)bk; int i=m->shwidx-bk; while(i<0)i+=m->shlen;
      int ip=i?i-1:m->shlen-1; float a=m->shbuf[i], b=m->shbuf[ip]; s0=a+(b-a)*fr; }
    { int bk=(int)p1; float fr=p1-(float)bk; int i=m->shwidx-bk; while(i<0)i+=m->shlen;
      int ip=i?i-1:m->shlen-1; float a=m->shbuf[i], b=m->shbuf[ip]; s1=a+(b-a)*fr; }
    float w0 = fast_sinf(3.14159265f * x0); w0 = w0*w0;
    if (++m->shwidx >= m->shlen) m->shwidx = 0;
    return s0*w0 + s1*(1.0f - w0);
}

microloop_t* microloop_create(double sample_rate) {
    const double sr = sample_rate > 0.0 ? sample_rate : AMB_REF_SAMPLE_RATE;
    microloop_t *m = (microloop_t*)calloc(1, sizeof(microloop_t));
    if (!m) return NULL;
    m->min_len       = amb_scale_samples(M_MIN_LEN_SAMPLES, sr);
    m->max_len       = amb_scale_samples(M_MAX_LEN_SAMPLES, sr);
    m->crossfade_len = amb_scale_samples(M_CROSSFADE_LEN, sr);
    m->smooth_c      = amb_scale_onepole(M_SMOOTH_COEF, sr);
    m->buf_capacity = m->max_len;
    m->buf = (short*)calloc((size_t)m->buf_capacity * 2, sizeof(short));
    if (!m->buf) { microloop_destroy(m); return NULL; }
    m->loop_len_current = m->min_len;
    m->loop_len_pending = m->min_len;
    m->loop_len_queued  = m->min_len;
    m->has_queued       = 0;
    m->xfade_remaining  = 0;
    m->hold = 0.0f;

    /* Octave shimmer buffer (~46 ms) + held-pad smoothing low-pass (~4.5 kHz). */
    m->shlen = amb_scale_samples(2048, sr);
    m->shbuf = (float*)calloc((size_t)m->shlen, sizeof(float));
    if (!m->shbuf) { microloop_destroy(m); return NULL; }
    m->shwidx = 0; m->shphase = 0.0f; m->shimmer_amt = 0.0f;
    m->lp_L = m->lp_R = 0.0f;
    m->lp_a1 = 1.0f - expf(-6.2831853f * 4500.0f / (float)sr);

    /* Freeze drone cloud state. */
    m->sr = sr;
    m->freeze_mix = 0.0f;
    m->freeze_mix_a = 1.0f - expf(-1.0f / (M_FREEZE_MIX_T * (float)sr));
    m->rng = 0x1234567u;
    m->spawn_timer = 0;
    m->cloud_tick = 0; m->cloud_l = m->cloud_r = 0.0f;
    for (int i = 0; i < M_GRAINS; i++) m->grain[i].active = 0;
    return m;
}

void microloop_destroy(microloop_t *m) {
    if (!m) return;
    free(m->buf);
    free(m->shbuf);
    free(m);
}

/* Clear the captured buffer + freeze/shimmer state (RT-safe). Keeps params. */
void microloop_reset(microloop_t *m) {
    if (!m) return;
    memset(m->buf, 0, (size_t)m->buf_capacity * 2 * sizeof(short));
    memset(m->shbuf, 0, (size_t)m->shlen * sizeof(float));
    m->write_pos = 0;
    m->fb_current = 0.0f;
    m->out_gain_current = 0.0f;
    m->lp_L = m->lp_R = 0.0f;
    m->shwidx = 0; m->shphase = 0.0f;
    m->xfade_remaining = 0; m->has_queued = 0;   /* cancel any in-flight re-anchor */
    m->reverse_current = 0.0f; m->rev_counter = 0;
    m->freeze_mix = 0.0f; m->spawn_timer = 0;
    m->cloud_tick = 0; m->cloud_l = m->cloud_r = 0.0f;
    for (int i = 0; i < M_GRAINS; i++) m->grain[i].active = 0;
}

/* Dilate: 0 = forward output, 1 = reversed (reverse-delay read). Smoothed. */
void microloop_set_reverse(microloop_t *m, float amount_0_1) {
    if (!m) return;
    if (amount_0_1 < 0.0f) amount_0_1 = 0.0f;
    if (amount_0_1 > 1.0f) amount_0_1 = 1.0f;
    m->reverse_target = amount_0_1;
}

/* Event Horizon: decay the active micro-loop window by `factor` (per block) so
 * lowering Horizon empties the buffer over time, not just ducks the output. */
void microloop_leak(microloop_t *m, float factor) {
    if (!m || factor >= 0.99999f) return;
    if (factor < 0.0f) factor = 0.0f;
    const int cap = m->buf_capacity;
    int len = m->loop_len_current; if (len < 1) len = 1; if (len > cap) len = cap;
    int idx = m->write_pos;
    for (int i = 0; i < len; i++) {
        if (--idx < 0) idx += cap;
        m->buf[idx*2]   = m_st(m_ld(m->buf[idx*2])   * factor);
        m->buf[idx*2+1] = m_st(m_ld(m->buf[idx*2+1]) * factor);
    }
}

void microloop_set_hold(microloop_t *m, float hold_0_1) {
    if (!m) return;
    if (hold_0_1 < 0.0f) hold_0_1 = 0.0f;
    if (hold_0_1 > 1.0f) hold_0_1 = 1.0f;
    m->hold = hold_0_1;
    /* Loop length is now set by the host (tempo-synced divisions) via
     * microloop_set_loop_len(); set_hold controls level / freeze / shimmer. */

    /* Gain targets — process() ramps current → target per sample.
     * Low/mid hold: a subtle 0.25×sqrt texture layer under the loop/reverb.
     * Near the top it swells into a prominent HELD PAD so the freeze/crystallize
     * actually sounds like the crystal glyph (held, frozen, pad). */
    float og = 0.25f * sqrtf(hold_0_1);
    if (hold_0_1 > 0.80f) {
        const float f = (hold_0_1 - 0.80f) / 0.20f;          /* 0..1 across 0.80..1.0 */
        const float base = 0.25f * sqrtf(0.80f);
        og = base + (0.34f - base) * f;                       /* gentle swell, not dominant */
    }
    m->out_gain_target = og;
    /* Feedback curve: a moderate floor so even a short delay gives a few musical
     * repeats (not a bare slapback), rising smoothly to long sustain near the top.
     * Linear (not steep) so short delays stay discrete echoes, not a dense comb. */
    m->fb_target = 0.55f + 0.40f * hold_0_1;     /* 0.55 .. 0.95 */

    /* Octave shimmer ramps in over the upper range (crystallize zone). */
    m->shimmer_amt = (hold_0_1 > 0.60f) ? ((hold_0_1 - 0.60f) / 0.40f) * 0.35f : 0.0f;
}

/* Set the micro-loop length in samples (host computes a continuous, tempo-
 * relative length). A change RE-ANCHORS the read tap via an equal-power
 * crossfade in process() (no pitch glide). If a fade is already running, the
 * newest request is queued and applied when it finishes — so a continuous knob
 * sweep chain-fades through lengths without ever sweeping the read pointer. */
void microloop_set_loop_len(microloop_t *m, int len) {
    if (!m) return;
    if (len < m->min_len) len = m->min_len;
    if (len > m->buf_capacity - 1) len = m->buf_capacity - 1;
    if (m->xfade_remaining > 0) {
        if (len != m->loop_len_pending) { m->loop_len_queued = len; m->has_queued = 1; }
        return;
    }
    if (len != m->loop_len_current) {
        m->loop_len_pending = len;
        m->xfade_remaining  = m->crossfade_len;
    }
}

void microloop_process(microloop_t *m,
                      const float *in_l, const float *in_r,
                      float *out_l, float *out_r,
                      int frames) {
    if (!m || frames <= 0) return;
    /* Auto-engage freeze when knob approaches max. */
    /* Audio freeze disabled: the micro-loop ALWAYS keeps capturing input (no
     * buffer freeze) so the top of Satellite stays the same kind of looping, not
     * a frozen drone. The held-pad grain cloud still ramps in via `hold > 0.85`
     * below (so the crystalline character — and the GUI crystal — remain). */
    const int frozen = 0;
    const int buf_capacity = m->buf_capacity;
    int write_pos = m->write_pos;

    /* Smoothed gains — ramp per sample toward target. */
    float fb_curr   = m->fb_current;
    float out_curr  = m->out_gain_current;
    const float fb_t  = m->fb_target;
    const float out_t = m->out_gain_target;
    const float c     = m->smooth_c;
    const float ic    = 1.0f - c;

    /* Held-pad low-pass amount: only the top zone gets smoothed, so short/mid
     * delays stay crisp & discrete (not a darkened, reverb-like smear). */
    float pad_amt = (m->hold - 0.80f) * (1.0f / 0.15f);
    if (pad_amt < 0.0f) pad_amt = 0.0f; if (pad_amt > 1.0f) pad_amt = 1.0f;

    for (int n = 0; n < frames; n++) {
        fb_curr  = c * fb_curr  + ic * fb_t;
        out_curr = c * out_curr + ic * out_t;

        /* Read at the active (fixed) tap. A length change crossfades to the new
         * tap over crossfade_len samples — both taps are at constant offsets, so
         * the read pointer never sweeps and there is no pitch glide. Equal-power
         * (cos/sin) because the two taps read decorrelated content. */
        int ra = write_pos - m->loop_len_current;
        if (ra < 0) ra += buf_capacity;
        float read_L = m_ld(m->buf[ra*2]);
        float read_R = m_ld(m->buf[ra*2+1]);
        if (m->xfade_remaining > 0) {
            int rb = write_pos - m->loop_len_pending;
            if (rb < 0) rb += buf_capacity;
            const float t  = (float)(m->crossfade_len - m->xfade_remaining)
                           * (1.0f / (float) m->crossfade_len);     /* 0..1 */
            const float gb = fast_sinf(t * 1.5707963f);
            const float ga = fast_cosf(t * 1.5707963f);
            read_L = ga * read_L + gb * m_ld(m->buf[rb*2]);
            read_R = ga * read_R + gb * m_ld(m->buf[rb*2+1]);
            if (--m->xfade_remaining == 0) {
                m->loop_len_current = m->loop_len_pending;          /* commit */
                if (m->has_queued && m->loop_len_queued != m->loop_len_current) {
                    m->loop_len_pending = m->loop_len_queued;
                    m->xfade_remaining  = m->crossfade_len;         /* chain next */
                }
                m->has_queued = 0;
            }
        }

        /* Dilate: crossfade the delay read to a reverse-delay read (two backward
         * heads offset by half the window, Hann-crossfaded → no seam, pitch kept).
         * Feeds the cloud/pad chain below so the reversed read still crystallises. */
        m->reverse_current = c * m->reverse_current + ic * m->reverse_target;
        if (m->reverse_current > 0.0005f) {
            int L = m->loop_len_current; if (L < 2) L = 2;
            float rL = 0.0f, rR = 0.0f;
            for (int h = 0; h < 2; h++) {
                int ph = m->rev_counter + (h ? L / 2 : 0);
                while (ph >= L) ph -= L;
                if (ph == 0) m->rev_base[h] = write_pos;
                int rabs = m->rev_base[h] - ph;
                while (rabs < 0) rabs += buf_capacity;
                const float gain = 0.5f - 0.5f * fast_cosf(6.2831853f * (float)ph / (float)L);
                rL += gain * m_ld(m->buf[rabs*2]);
                rR += gain * m_ld(m->buf[rabs*2+1]);
            }
            const float rc = m->reverse_current;
            read_L = (1.0f - rc) * read_L + rc * rL;
            read_R = (1.0f - rc) * read_R + rc * rR;
        }
        { int Lw = m->loop_len_current < 2 ? 2 : m->loop_len_current;
          m->rev_counter++; if (m->rev_counter >= Lw) m->rev_counter = 0; }

        /* Seamless held-pad via the granular cloud. Hann-windowed overlapping
         * grains taper the edges so the sustained pad has no loop seam. Only
         * engaged in the top held-pad zone (hold > 0.85) and fully when frozen
         * — short/medium delays keep the crisp DIRECT read so they stay
         * discrete echoes, not a smeared reverb-like wash. */
        float cloud_target = frozen ? 1.0f : 0.0f;
        if (m->hold > 0.85f) {
            float s = (m->hold - 0.85f) * (1.0f / 0.10f);
            if (s > 1.0f) s = 1.0f;
            if (s > cloud_target) cloud_target = s;
        }
        m->freeze_mix += m->freeze_mix_a * (cloud_target - m->freeze_mix);
#ifndef AMB_NO_CLOUD
        if (m->freeze_mix > 0.0001f) {
            /* Half-rate: the cloud is a smeared granular wash, so recompute it every
             * other sample (advancing grains by 2) and hold between — halves its
             * scattered PSRAM grain reads, the dominant cost, and is inaudible on a
             * wash. (Shimmer stays full-rate: it's octave-up, would alias at 16 kHz.) */
            if ((m->cloud_tick ^= 1))
                micro_cloud(m, cloud_target > 0.0f, write_pos, 2, &m->cloud_l, &m->cloud_r);
            read_L += (m->cloud_l - read_L) * m->freeze_mix;
            read_R += (m->cloud_r - read_R) * m->freeze_mix;
        } else {
            m->cloud_tick = 0;         /* start next freeze on a compute sample */
        }
#endif

        /* Output: ONLY the loop content. Caller mixes in dry passthrough.
         * Held-pad smoothing: a one-pole low-pass blended in by `hold` so the
         * sustained/crystallized pad is smooth (less seam grain) while short
         * echoes stay crisp; then octave shimmer on top for the glassy sheen. */
        float oL = out_curr * read_L;
        float oR = out_curr * read_R;
        m->lp_L += m->lp_a1 * (oL - m->lp_L);
        m->lp_R += m->lp_a1 * (oR - m->lp_R);
        oL += (m->lp_L - oL) * pad_amt;
        oR += (m->lp_R - oR) * pad_amt;
#ifndef AMB_NO_SHIMMER
        if (m->shimmer_amt > 0.0f) {
            float sh = micro_shimmer (m, (oL + oR) * 0.5f);
            oL += m->shimmer_amt * sh;
            oR += m->shimmer_amt * sh;
        }
#endif
        out_l[n] = oL;
        out_r[n] = oR;

        /* Write input + feedback into buffer unless frozen. */
        if (!frozen) {
            float new_L = in_l[n] + fb_curr * read_L;
            float new_R = in_r[n] + fb_curr * read_R;
            if (new_L >  1.0f) new_L =  1.0f; else if (new_L < -1.0f) new_L = -1.0f;
            if (new_R >  1.0f) new_R =  1.0f; else if (new_R < -1.0f) new_R = -1.0f;
            m->buf[write_pos*2]   = m_st(new_L);
            m->buf[write_pos*2+1] = m_st(new_R);
        }

        write_pos++;
        if (write_pos >= buf_capacity) write_pos = 0;
    }
    m->write_pos = write_pos;
    m->fb_current = fb_curr;
    m->out_gain_current = out_curr;
}
/* Ambiotica harmony — see harmony.h. */

#define H_MIN_FREQ   28.0f    /* lowest tunable note -> biggest delay buffer */
#define H_IN_GAIN    0.22f    /* plugin value (excitation into each high-Q resonator) */
#define H_SMOOTH     0.0008f  /* per-sample glide of delay length (no zipper)  */

struct harmony_s {
    double sr;
    float *buf[HARMONY_MAX_VOICES];   /* mono comb delay line per voice */
    int    buflen;
    int    widx;

    float  delay[HARMONY_MAX_VOICES];        /* current fractional delay (samples) */
    float  delay_target[HARMONY_MAX_VOICES]; /* requested delay                    */
    float  lp[HARMONY_MAX_VOICES];           /* damping one-pole state             */
    float  gL[HARMONY_MAX_VOICES], gR[HARMONY_MAX_VOICES];  /* per-voice pan        */
    int    n_voices;
    float  damp_a;                  /* damping cutoff coef */
    float  amount, amount_sm, amount_a;
    float  fb;                      /* resonator feedback (ring length) */
    float  out_gain;
};

harmony_t* harmony_create(double sample_rate) {
    harmony_t *h = (harmony_t*) calloc(1, sizeof(harmony_t));
    if (!h) return NULL;
    h->sr = sample_rate > 0.0 ? sample_rate : 44100.0;
    h->buflen = (int)(h->sr / H_MIN_FREQ) + 4;
    for (int v = 0; v < HARMONY_MAX_VOICES; v++) {
        h->buf[v] = (float*) calloc((size_t) h->buflen, sizeof(float));
        if (!h->buf[v]) { harmony_destroy(h); return NULL; }
        h->delay[v] = h->delay_target[v] = (float)(h->sr / 220.0);  /* A3 default */
        /* spread voices L..R */
        float pan = (HARMONY_MAX_VOICES > 1) ? (float) v / (float)(HARMONY_MAX_VOICES - 1) : 0.5f;
        float th = (0.5f + (pan - 0.5f) * 0.8f) * 1.5707963f;       /* keep both chans */
        h->gL[v] = fast_cosf(th); h->gR[v] = fast_sinf(th);
    }
    h->n_voices = 0;
    /* damping ~8 kHz one-pole — bright, long ring (still tames the very top) */
    h->damp_a   = 1.0f - expf(-6.2831853f * 8000.0f / (float) h->sr);
    h->amount_a = 1.0f - expf(-1.0f / (0.020f * (float) h->sr));     /* ~20 ms */
    h->fb       = 0.995f;           /* default ring length (see harmony_set_ring) */
    h->out_gain = 1.25f;            /* plugin value (chord level in the wash) */
    return h;
}

void harmony_destroy(harmony_t *h) {
    if (!h) return;
    for (int v = 0; v < HARMONY_MAX_VOICES; v++) free(h->buf[v]);
    free(h);
}

void harmony_reset(harmony_t *h) {
    if (!h) return;
    for (int v = 0; v < HARMONY_MAX_VOICES; v++) {
        memset(h->buf[v], 0, (size_t) h->buflen * sizeof(float));
        h->lp[v] = 0.0f;
    }
    h->widx = 0; h->amount_sm = 0.0f;
}

void harmony_set_chord(harmony_t *h, const float *freqs, int n) {
    if (!h || !freqs) return;
    if (n < 0) n = 0; if (n > HARMONY_MAX_VOICES) n = HARMONY_MAX_VOICES;
    const int prev = h->n_voices;      /* voices already ringing at a pitch */
    h->n_voices = n;
    for (int v = 0; v < n; v++) {
        float f = freqs[v];
        if (f < H_MIN_FREQ) f = H_MIN_FREQ;
        float d = (float)(h->sr / (double) f);
        if (d > (float)(h->buflen - 2)) d = (float)(h->buflen - 2);
        if (d < 2.0f) d = 2.0f;
        h->delay_target[v] = d;
        /* Newly-voiced note: SNAP the delay to pitch instead of gliding from the
         * A3 create-time default — that glide was an audible downward swoop each
         * time the chord first engaged. Voices already ringing still glide (so a
         * future key change bends smoothly rather than clicks). */
        if (v >= prev) h->delay[v] = d;
    }
}

/* Ring length: 0 = shorter/plucky, 1 = long (but still finite) sustained chord.
 * Capped below self-sustain so the chord always dies out when input stops. */
void harmony_set_ring(harmony_t *h, float ring_0_1) {
    if (!h) return;
    if (ring_0_1 < 0.0f) ring_0_1 = 0.0f;
    if (ring_0_1 > 1.0f) ring_0_1 = 1.0f;
    /* The Dattorro wash feeding these resonators is ~13x hotter than the plugin's reverb
     * (tap 0.95 vs wet_gain 0.18), so the plugin's max Q (fb 0.993) drives them into a
     * sustained, saturated resonance at high Tail that keeps building and rings on the
     * chord pitches. Cap the Q lower so the ring decays in a finite time and can't
     * self-sustain against the wash. (Harness uses the same Dattorro, so no need to gate.) */
    h->fb = 0.982f + 0.005f * ring_0_1;   /* 0.982 .. 0.987 */
}

void harmony_set_amount(harmony_t *h, float amount) {
    if (!h) return;
    if (amount < 0.0f) amount = 0.0f;
    if (amount > 1.0f) amount = 1.0f;
    h->amount = amount;
}

static inline float h_read(const float *buf, int len, int widx, float delay) {
    float rp = (float) widx - delay;
    while (rp < 0.0f) rp += (float) len;
    int i0 = (int) rp; float fr = rp - (float) i0;
    int i1 = i0 + 1; if (i1 >= len) i1 = 0;
    return buf[i0] + (buf[i1] - buf[i0]) * fr;
}

void harmony_process(harmony_t *h,
                     const float *in_l, const float *in_r,
                     float *out_l, float *out_r,
                     int frames) {
    if (!h || frames <= 0) return;

    /* Bypass once fully ramped down and inactive (parity-safe default). */
    if (h->amount <= 0.0f && h->amount_sm <= 1.0e-5f) {
        h->amount_sm = 0.0f;
        for (int n = 0; n < frames; n++) { out_l[n] = in_l[n]; out_r[n] = in_r[n]; }
        return;
    }

    const int nv = h->n_voices;
    const int len = h->buflen;
    int widx = h->widx;
    float a = h->amount_sm;
    const float aa = h->amount_a, at = h->amount;
    const float fb = h->fb, ig = H_IN_GAIN, da = h->damp_a, og = h->out_gain;

    for (int n = 0; n < frames; n++) {
        a += aa * (at - a);
        const float inMono = 0.5f * (in_l[n] + in_r[n]);
        float oL = 0.0f, oR = 0.0f;
        for (int v = 0; v < nv; v++) {
            h->delay[v] += H_SMOOTH * (h->delay_target[v] - h->delay[v]);   /* glide */
            float r = h_read(h->buf[v], len, widx, h->delay[v]);
            h->lp[v] += da * (r - h->lp[v]);                /* damp the feedback */
            /* High-Q resonator WITH gain at resonance (sings the pitch out of
             * the broadband wash); tanh keeps the ring from howling. */
            h->buf[v][widx] = ig * inMono + fast_tanhf(fb * h->lp[v]);
            oL += r * h->gL[v];
            oR += r * h->gR[v];
        }
        /* ADD the resonated chord on top of the wash (don't replace it), so
         * turning Harmony up layers the chord without killing the reverb. */
        out_l[n] = in_l[n] + a * oL * og;
        out_r[n] = in_r[n] + a * oR * og;
        widx++; if (widx >= len) widx = 0;
    }

    h->widx = widx;
    h->amount_sm = a;
}
/* Ambiotica bloom — see bloom.h. */

/* Follower time constants (seconds). The fast follower tracks the true
 * envelope; the slow follower's ATTACK is what the knob stretches. Both use a
 * fast release so that when a sound decays the ratio returns to 1 and tails are
 * never ducked. */
#define BLOOM_FAST_T      0.0020f   /* 2 ms — fast envelope attack & release */
#define BLOOM_SLOW_REL_T  0.0050f   /* 5 ms — slow follower release          */
#define BLOOM_SLOW_ATK_MIN 0.0020f  /* amount=0 → equals fast → bypass        */
#define BLOOM_SLOW_ATK_MAX 2.0000f  /* amount=1 → ~2 s bowed swell            */
#define BLOOM_GAIN_T      0.0050f   /* 5 ms smoothing on the applied gain     */
#define BLOOM_EPS         1.0e-6f

struct bloom_s {
    double sr;
    float  amount;

    float  env_fast_l, env_fast_r;   /* fast |x| follower            */
    float  env_slow_l, env_slow_r;   /* slow-attack |x| follower     */
    float  gain_l, gain_r;           /* smoothed applied gain        */

    float  fast_a;                   /* fast attack/release coef     */
    float  slow_atk_a;               /* slow follower attack coef    */
    float  slow_rel_a;               /* slow follower release coef   */
    float  gain_a;                   /* gain smoothing coef          */
};

/* One-pole coefficient for a time constant (a = exp(-1/(t*sr))). */
static float coef_for(float t_seconds, double sr) {
    if (t_seconds <= 0.0f) return 0.0f;
    return expf(-1.0f / ((float) t_seconds * (float) sr));   /* expf: wasm toolchain has no double exp */
}

bloom_t* bloom_create(double sample_rate) {
    bloom_t *b = (bloom_t*) calloc(1, sizeof(bloom_t));
    if (!b) return NULL;
    b->sr = sample_rate > 0.0 ? sample_rate : 44100.0;
    b->fast_a    = coef_for(BLOOM_FAST_T, b->sr);
    b->slow_rel_a = coef_for(BLOOM_SLOW_REL_T, b->sr);
    b->gain_a    = coef_for(BLOOM_GAIN_T, b->sr);
    b->gain_l = b->gain_r = 1.0f;
    bloom_set_amount(b, 0.0f);
    return b;
}

void bloom_destroy(bloom_t *b) { free(b); }

/* Clear the follower/gain state (RT-safe). Keeps the amount setting. */
void bloom_reset(bloom_t *b) {
    if (!b) return;
    b->env_fast_l = b->env_fast_r = 0.0f;
    b->env_slow_l = b->env_slow_r = 0.0f;
    b->gain_l = b->gain_r = 1.0f;
}

void bloom_set_amount(bloom_t *b, float amount) {
    if (!b) return;
    if (amount < 0.0f) amount = 0.0f;
    if (amount > 1.0f) amount = 1.0f;
    b->amount = amount;
    /* Curve the swell time so the knob feels musical (more travel up high). */
    float t = BLOOM_SLOW_ATK_MIN +
              (BLOOM_SLOW_ATK_MAX - BLOOM_SLOW_ATK_MIN) * (amount * amount);
    b->slow_atk_a = coef_for(t, b->sr);
}

/* Asymmetric one-pole follower of a rectified sample. */
static inline float follow(float env, float x, float a_atk, float a_rel) {
    float a = (x > env) ? a_atk : a_rel;
    return a * env + (1.0f - a) * x;
}

void bloom_process(bloom_t *b,
                   const float *in_l, const float *in_r,
                   float *out_l, float *out_r,
                   int frames) {
    if (!b || frames <= 0) return;

    /* True bypass at amount 0 — identical to input (parity-safe default). */
    if (b->amount <= 0.0f) {
        for (int n = 0; n < frames; n++) { out_l[n] = in_l[n]; out_r[n] = in_r[n]; }
        return;
    }

    float ef_l = b->env_fast_l, ef_r = b->env_fast_r;
    float es_l = b->env_slow_l, es_r = b->env_slow_r;
    float g_l  = b->gain_l,     g_r  = b->gain_r;
    const float fa = b->fast_a, sa = b->slow_atk_a, sr_ = b->slow_rel_a, ga = b->gain_a;

    for (int n = 0; n < frames; n++) {
        float xl = in_l[n], xr = in_r[n];
        float al = fabsf(xl), ar = fabsf(xr);

        ef_l = follow(ef_l, al, fa, fa);
        ef_r = follow(ef_r, ar, fa, fa);
        es_l = follow(es_l, al, sa, sr_);
        es_r = follow(es_r, ar, sa, sr_);

        /* Gain = slow/fast, clamped to 1: <1 during onsets, →1 once the swell
         * completes and during decays. */
        float tg_l = es_l / (ef_l + BLOOM_EPS);
        float tg_r = es_r / (ef_r + BLOOM_EPS);
        if (tg_l > 1.0f) tg_l = 1.0f;
        if (tg_r > 1.0f) tg_r = 1.0f;

        g_l = ga * g_l + (1.0f - ga) * tg_l;
        g_r = ga * g_r + (1.0f - ga) * tg_r;

        out_l[n] = xl * g_l;
        out_r[n] = xr * g_r;
    }

    b->env_fast_l = ef_l; b->env_fast_r = ef_r;
    b->env_slow_l = es_l; b->env_slow_r = es_r;
    b->gain_l = g_l;      b->gain_r = g_r;
}
/* Ambiotica drift — see drift.h. */

#define DRIFT_TWO_PI      6.28318530717958647692f
/* Very slow, slightly-different L/R rates so the wander is wide and organic. */
#define DRIFT_RATE_L      0.070f    /* Hz */
#define DRIFT_RATE_R      0.083f    /* Hz */
#define DRIFT_DEPTH_MAX   380.0f    /* peak delay swing (samples) at amount=1   */
#define DRIFT_CENTER_PAD  24.0f     /* keep the read head off the write head    */

struct drift_s {
    double sr;
    float  amount;

    float *buf_l, *buf_r;
    int    buf_len;
    int    widx;

    float  phase_l, phase_r;       /* 0..1 LFO phases            */
    float  inc_l,   inc_r;         /* per-sample phase increment */
    float  center;                 /* max nominal delay (samples, rate-scaled) */
    float  depth_max;              /* peak mod swing (samples, rate-scaled)    */
    float  amount_target;          /* knob target (0..1)         */
    float  amount_sm;              /* per-sample smoothed amount  */
    float  amount_a;               /* smoothing coef (~30 ms)    */
};

drift_t* drift_create(double sample_rate) {
    drift_t *d = (drift_t*) calloc(1, sizeof(drift_t));
    if (!d) return NULL;
    d->sr = sample_rate > 0.0 ? sample_rate : 44100.0;

    /* DRIFT_DEPTH_MAX / _PAD are SAMPLES at 44.1 kHz; scale to the host rate so
     * the pitch "wow" is time-constant across sample rates. Without this the
     * 380-sample swing is ~50% DEEPER at Plinky's 32 kHz than in the plugin
     * (a stronger Flux wobble on the sustained wash/chord). The LFO rate is
     * already in Hz (inc = RATE/sr), so only the depth needs scaling. */
    const float rk = (float) (d->sr / 44100.0);
    d->depth_max = DRIFT_DEPTH_MAX * rk;
    d->center    = d->depth_max + DRIFT_CENTER_PAD * rk;
    d->buf_len   = (int) (2.0f * d->center + 4.0f);

    d->buf_l = (float*) calloc((size_t) d->buf_len, sizeof(float));
    d->buf_r = (float*) calloc((size_t) d->buf_len, sizeof(float));
    if (!d->buf_l || !d->buf_r) { drift_destroy(d); return NULL; }

    d->inc_l = (float) (DRIFT_RATE_L / d->sr);
    d->inc_r = (float) (DRIFT_RATE_R / d->sr);
    d->phase_r = 0.25f;            /* start in quadrature */
    d->amount_a = 1.0f - expf(-1.0f / (0.030f * (float) d->sr));   /* ~30 ms; expf (no double exp on wasm) */
    d->amount_sm = 0.0f;
    drift_set_amount(d, 0.0f);
    return d;
}

void drift_destroy(drift_t *d) {
    if (!d) return;
    free(d->buf_l); free(d->buf_r); free(d);
}

/* Clear the delay buffer + smoothing state (RT-safe). Keeps the amount target. */
void drift_reset(drift_t *d) {
    if (!d) return;
    memset(d->buf_l, 0, (size_t)d->buf_len * sizeof(float));
    memset(d->buf_r, 0, (size_t)d->buf_len * sizeof(float));
    d->widx = 0;
    d->amount_sm = 0.0f;
}

void drift_set_amount(drift_t *d, float amount) {
    if (!d) return;
    if (amount < 0.0f) amount = 0.0f;
    if (amount > 1.0f) amount = 1.0f;
    d->amount = amount;
    d->amount_target = amount;     /* process() ramps amount_sm toward this */
}

/* Fractional read from a delay line, `delay` samples behind the write head. */
static inline float read_frac(const float *buf, int len, int widx, float delay) {
    float rp = (float) widx - delay;
    while (rp < 0.0f)        rp += (float) len;
    while (rp >= (float) len) rp -= (float) len;
    int i0 = (int) rp;
    int i1 = i0 + 1; if (i1 >= len) i1 = 0;
    float f = rp - (float) i0;
    return buf[i0] + (buf[i1] - buf[i0]) * f;
}

void drift_process(drift_t *d,
                  const float *in_l, const float *in_r,
                  float *out_l, float *out_r,
                  int frames) {
    if (!d || frames <= 0) return;

    /* Bypass only once fully ramped down (parity-safe default). */
    if (d->amount_target <= 0.0f && d->amount_sm <= 1.0e-5f) {
        d->amount_sm = 0.0f;
        for (int n = 0; n < frames; n++) { out_l[n] = in_l[n]; out_r[n] = in_r[n]; }
        return;
    }

    int widx = d->widx, len = d->buf_len;
    float pl = d->phase_l, pr = d->phase_r;
    const float il = d->inc_l, ir = d->inc_r;
    const float center = d->center;
    const float dm = d->depth_max;
    float a = d->amount_sm;
    const float aa = d->amount_a, at = d->amount_target;

    for (int n = 0; n < frames; n++) {
        d->buf_l[widx] = in_l[n];
        d->buf_r[widx] = in_r[n];

        a += aa * (at - a);                 /* smooth knob changes (no zipper) */

        /* Nominal delay and modulation depth both scale with the smoothed
         * amount, so the read head grows out from 0 as Drift comes up — no
         * bypass click and no comb at low settings. */
        float ml = fast_sinf(DRIFT_TWO_PI * pl);
        float mr = fast_sinf(DRIFT_TWO_PI * pr);
        float dlyL = center * a + dm * a * ml;
        float dlyR = center * a + dm * a * mr;
        if (dlyL < 0.0f) dlyL = 0.0f;
        if (dlyR < 0.0f) dlyR = 0.0f;

        out_l[n] = read_frac(d->buf_l, len, widx, dlyL);
        out_r[n] = read_frac(d->buf_r, len, widx, dlyR);

        pl += il; if (pl >= 1.0f) pl -= 1.0f;
        pr += ir; if (pr >= 1.0f) pr -= 1.0f;
        widx++;   if (widx >= len) widx = 0;
    }

    d->widx = widx; d->phase_l = pl; d->phase_r = pr; d->amount_sm = a;
}

#ifndef M_PI
#define M_PI 3.14159265358979323846
#endif
#define TWO_PI (2.0f * (float)M_PI)

void lfo_init(lfo_t *lfo, int sample_rate) {
    if (!lfo) return;
    lfo->phase = 0.0f;
    lfo->increment = 0.0f;
    lfo->sample_rate = sample_rate > 0 ? sample_rate : 44100;
}

void lfo_set_rate_hz(lfo_t *lfo, float hz) {
    if (!lfo) return;
    if (hz < 0.0f) hz = 0.0f;
    lfo->increment = TWO_PI * hz / (float)lfo->sample_rate;
}

void lfo_set_phase(lfo_t *lfo, float radians) {
    if (!lfo) return;
    while (radians < 0.0f)    radians += TWO_PI;
    while (radians >= TWO_PI) radians -= TWO_PI;
    lfo->phase = radians;
}

float lfo_tick_sine(lfo_t *lfo) {
    if (!lfo) return 0.0f;
    float y = fast_sinf(lfo->phase);
    lfo->phase += lfo->increment;
    if (lfo->phase >= TWO_PI) lfo->phase -= TWO_PI;
    return y;
}

float lfo_sine_at_offset(const lfo_t *lfo, float radian_offset) {
    if (!lfo) return 0.0f;
    return fast_sinf(lfo->phase + radian_offset);
}

float lfo_shape_apply(int shape, float sine) {
    /* sine ∈ [-1, +1]. Output ∈ [-1, +1] for sine; warp & sink remap to a
     * unipolar range centered on a DC offset that biases the modulation in
     * one direction. */
    switch (shape) {
        case 1:  /* Warp: 0..+1, pitch always biased up */
            return 0.5f * (1.0f + sine);
        case 2:  /* Sink: -1..0, pitch always biased down */
            return 0.5f * (sine - 1.0f);
        case 0:
        default:
            return sine;
    }
}
/* Dattorro plate reverb — see dattorro.h. */

/* Reference delay lengths from Dattorro's paper, at his 29761 Hz clock. Scaled to
 * the plate's internal (half host) rate in dattorro_create(). */
#define DREF_SR       29761.0f
static const int IN_AP[4]   = { 142, 107, 379, 277 };   /* input diffusers */
static const int MODAP[2]   = { 672, 908 };             /* decay diffusion 1 (modulated) */
static const int DELAYA[2]  = { 4453, 4217 };
static const int AP2[2]     = { 1800, 2656 };           /* decay diffusion 2 */
static const int DELAYB[2]  = { 3720, 3163 };
/* Output taps: {line, offset} pairs. line: 0..1 delayA L/R, 2..3 ap2 L/R, 4..5 delayB L/R. */
static const int TAP_L[7][2] = { {1,266},{1,2974},{3,1913},{5,1996},{0,1990},{2,187},{4,1066} };
static const int TAP_L_SGN[7] = { +1,+1,-1,+1,-1,-1,-1 };
static const int TAP_R[7][2] = { {0,353},{0,3627},{2,1228},{4,2673},{1,2111},{3,335},{5,121} };
static const int TAP_R_SGN[7] = { +1,+1,-1,+1,-1,-1,-1 };

/* ------- delay line (ring buffer): read `offset` samples ago, then write+advance -- */
typedef struct { float* buf; int len; int pos; } dline;

struct dattorro_s {
    double sr;
    float  scale;                 /* DREF_SR-samples -> internal-rate samples */
    int    inap_len[4], modap_len[2], da_len[2], ap2_len[2], db_len[2];
    dline  inap[4];               /* input diffusers */
    dline  modap[2], da[2], ap2[2], db[2];   /* tank: L=0, R=1 */
    int    tapL[7], tapR[7];      /* scaled tap offsets */
    float  bw_lp;                 /* input bandwidth one-pole */
    float  hp_lp, hp_a;           /* input sub-bass high-pass (keeps low notes from building mud) */
    float  damp_lp[2];            /* tank damping one-pole (L,R) */
    float  lfo_ph[2];             /* two slow modulation LFOs */
    float  lfo_inc;
    /* params */
    float  decay, dd1, dd2, damp_a, bw, mod_depth;
    /* half-rate upsample hold */
    float  holdL, holdR;
};

static int dl_alloc(dline* d, int len) {
    if (len < 2) len = 2;
    d->buf = (float*)calloc((size_t)len, sizeof(float));
    d->len = len; d->pos = 0;
    return d->buf != NULL;
}
static inline float dl_read(const dline* d, int offset) {
    int i = d->pos - offset; if (i < 0) i += d->len;
    return d->buf[i];
}
static inline float dl_read_frac(const dline* d, float offset) {
    int i0 = (int)offset; float fr = offset - (float)i0;
    int a = d->pos - i0;     if (a < 0) a += d->len;
    int b = a - 1;           if (b < 0) b += d->len;
    return d->buf[a] + (d->buf[b] - d->buf[a]) * fr;
}
static inline void dl_write(dline* d, float x) {
    d->buf[d->pos] = x; d->pos++; if (d->pos >= d->len) d->pos = 0;
}
/* Schroeder allpass over a delay line (stores the recirculating v). */
static inline float ap_tick(dline* d, int D, float in, float g) {
    float vd = dl_read(d, D);
    float v  = in + g * vd;
    dl_write(d, v);
    return -g * v + vd;
}
static inline float modap_tick(dline* d, int D, float in, float g, float modsamp) {
    float vd = dl_read_frac(d, (float)D + modsamp);
    float v  = in + g * vd;
    dl_write(d, v);
    return -g * v + vd;
}
/* pure delay: output = input D samples ago. */
static inline float delay_tick(dline* d, int D, float in) {
    float o = dl_read(d, D);
    dl_write(d, in);
    return o;
}

static int scl(dattorro_t* d, int ref) { int v = (int)(ref * d->scale + 0.5f); return v < 1 ? 1 : v; }

dattorro_t* dattorro_create(double sample_rate) {
    dattorro_t* d = (dattorro_t*)calloc(1, sizeof(dattorro_t));
    if (!d) return NULL;
    d->sr    = sample_rate > 0 ? sample_rate : 32000.0;
    float internal = (float)(d->sr * 0.5);          /* plate runs at half host rate */
    d->scale = internal / DREF_SR;
    /* modulation: ~1.0 Hz LFOs at the internal rate */
    d->lfo_inc = 6.2831853f * 1.0f / internal;
    d->lfo_ph[0] = 0.0f; d->lfo_ph[1] = 2.3f;
    /* delay lengths */
    int ok = 1;
    for (int i = 0; i < 4; i++) { d->inap_len[i] = scl(d, IN_AP[i]); ok &= dl_alloc(&d->inap[i], d->inap_len[i] + 2); }
    const int modroom = (int)(0.020f * internal) + 4;   /* ~20 ms mod headroom */
    for (int c = 0; c < 2; c++) {
        d->modap_len[c] = scl(d, MODAP[c]);   ok &= dl_alloc(&d->modap[c], d->modap_len[c] + modroom);
        d->da_len[c]    = scl(d, DELAYA[c]);  ok &= dl_alloc(&d->da[c],    d->da_len[c]  + 2);
        d->ap2_len[c]   = scl(d, AP2[c]);     ok &= dl_alloc(&d->ap2[c],   d->ap2_len[c] + 2);
        d->db_len[c]    = scl(d, DELAYB[c]);  ok &= dl_alloc(&d->db[c],    d->db_len[c]  + 2);
    }
    for (int i = 0; i < 7; i++) { d->tapL[i] = scl(d, TAP_L[i][1]); d->tapR[i] = scl(d, TAP_R[i][1]); }
    if (!ok) { dattorro_destroy(d); return NULL; }
    d->dd1 = 0.70f; d->bw = 0.9995f; d->mod_depth = 0.5f;
    d->hp_a = 1.0f - expf(-6.2831853f * 80.0f / internal);   /* 80 Hz sub-bass HP — matches the
                                                                plugin reverb (R_HPF_LP_COEF): stops
                                                                sub-80 Hz piling up in the tail */
    dattorro_set_decay(d, 0.5f);
    dattorro_set_damp(d, 0.35f);
    return d;
}

void dattorro_destroy(dattorro_t* d) {
    if (!d) return;
    for (int i = 0; i < 4; i++) free(d->inap[i].buf);
    for (int c = 0; c < 2; c++) { free(d->modap[c].buf); free(d->da[c].buf); free(d->ap2[c].buf); free(d->db[c].buf); }
    free(d);
}

void dattorro_reset(dattorro_t* d) {
    if (!d) return;
    for (int i = 0; i < 4; i++) memset(d->inap[i].buf, 0, (size_t)d->inap[i].len * sizeof(float));
    for (int c = 0; c < 2; c++) {
        memset(d->modap[c].buf, 0, (size_t)d->modap[c].len * sizeof(float));
        memset(d->da[c].buf,    0, (size_t)d->da[c].len    * sizeof(float));
        memset(d->ap2[c].buf,   0, (size_t)d->ap2[c].len   * sizeof(float));
        memset(d->db[c].buf,    0, (size_t)d->db[c].len    * sizeof(float));
    }
    d->bw_lp = d->hp_lp = d->damp_lp[0] = d->damp_lp[1] = 0.0f;
    d->holdL = d->holdR = 0.0f;
}

void dattorro_set_decay(dattorro_t* d, float x) {
    if (!d) return; if (x < 0) x = 0; if (x > 1) x = 1;
    /* map to internal decay 0.40 .. 0.95 -> RT60 ~1.1..~12 s, tracking the plugin
     * reverb (measured 1.34..12.45 s) and capped short of self-oscillation. */
    d->decay = 0.40f + 0.55f * x;
    d->dd2   = 0.15f + d->decay; if (d->dd2 > 0.50f) d->dd2 = 0.50f; if (d->dd2 < 0.25f) d->dd2 = 0.25f;
}
void dattorro_set_damp(dattorro_t* d, float x) {
    if (!d) return; if (x < 0) x = 0; if (x > 1) x = 1;
    /* damp_a = per-sample one-pole retention of the feedback low-pass. 1 = bright. */
    d->damp_a = 1.0f - (0.05f + 0.85f * x);   /* 0.95 (bright) .. 0.10 (dark) */
}
void dattorro_set_mod(dattorro_t* d, float x) {
    if (!d) return; if (x < 0) x = 0; if (x > 1) x = 1;
    d->mod_depth = x;
}

/* One half-rate stereo tick. */
static inline void dattorro_tick(dattorro_t* d, float inL, float inR, float* yl, float* yr) {
    float mono = 0.5f * (inL + inR);
    d->hp_lp += d->hp_a * (mono - d->hp_lp);   /* high-pass: drop sub-bass so long notes don't build mud */
    mono -= d->hp_lp;
    d->bw_lp += d->bw * (mono - d->bw_lp);
    float x = d->bw_lp;
    x = ap_tick(&d->inap[0], d->inap_len[0], x, 0.75f);
    x = ap_tick(&d->inap[1], d->inap_len[1], x, 0.75f);
    x = ap_tick(&d->inap[2], d->inap_len[2], x, 0.625f);
    x = ap_tick(&d->inap[3], d->inap_len[3], x, 0.625f);

    d->lfo_ph[0] += d->lfo_inc; if (d->lfo_ph[0] > 6.2831853f) d->lfo_ph[0] -= 6.2831853f;
    d->lfo_ph[1] += d->lfo_inc; if (d->lfo_ph[1] > 6.2831853f) d->lfo_ph[1] -= 6.2831853f;
    float modA = (0.5f + 0.5f * fast_sinf(d->lfo_ph[0])) * d->mod_depth * 12.0f;   /* 0..~12 samples */
    float modB = (0.5f + 0.5f * fast_sinf(d->lfo_ph[1])) * d->mod_depth * 12.0f;

    float fbL = dl_read(&d->db[0], d->db_len[0]);   /* delayed outputs of each half */
    float fbR = dl_read(&d->db[1], d->db_len[1]);
    const float dec = d->decay;

    /* LEFT half: fed by the RIGHT half's tail */
    float a = x + dec * fbR;
    a = modap_tick(&d->modap[0], d->modap_len[0], a, d->dd1, modA);
    a = delay_tick(&d->da[0], d->da_len[0], a);
    d->damp_lp[0] += d->damp_a * (a - d->damp_lp[0]); a = d->damp_lp[0];
    a *= dec;
    a = ap_tick(&d->ap2[0], d->ap2_len[0], a, d->dd2);
    dl_write(&d->db[0], a);

    /* RIGHT half: fed by the LEFT half's tail */
    float b = x + dec * fbL;
    b = modap_tick(&d->modap[1], d->modap_len[1], b, d->dd1, modB);
    b = delay_tick(&d->da[1], d->da_len[1], b);
    d->damp_lp[1] += d->damp_a * (b - d->damp_lp[1]); b = d->damp_lp[1];
    b *= dec;
    b = ap_tick(&d->ap2[1], d->ap2_len[1], b, d->dd2);
    dl_write(&d->db[1], b);

    /* multi-tap stereo output */
    const dline* line[6] = { &d->da[0], &d->da[1], &d->ap2[0], &d->ap2[1], &d->db[0], &d->db[1] };
    float ol = 0.f, orr = 0.f;
    for (int i = 0; i < 7; i++) {
        ol  += TAP_L_SGN[i] * dl_read(line[TAP_L[i][0]], d->tapL[i]);
        orr += TAP_R_SGN[i] * dl_read(line[TAP_R[i][0]], d->tapR[i]);
    }
    *yl = ol * 0.95f; *yr = orr * 0.95f;   /* tap sum -> wet level (louder wash + more Spectra drive) */
}

void dattorro_process(dattorro_t* d, const float* in_l, const float* in_r,
                      float* out_l, float* out_r, int n) {
    if (!d) { for (int i = 0; i < n; i++) { out_l[i] = out_r[i] = 0.f; } return; }
    for (int i = 0; i < n; i += 2) {
        float il = 0.5f * (in_l[i] + (i + 1 < n ? in_l[i + 1] : in_l[i]));   /* 32k -> 16k decimate */
        float ir = 0.5f * (in_r[i] + (i + 1 < n ? in_r[i + 1] : in_r[i]));
        float wl, wr;
        dattorro_tick(d, il, ir, &wl, &wr);
        out_l[i] = 0.5f * (d->holdL + wl);          /* 16k -> 32k linear upsample */
        out_r[i] = 0.5f * (d->holdR + wr);
        if (i + 1 < n) { out_l[i + 1] = wl; out_r[i + 1] = wr; }
        d->holdL = wl; d->holdR = wr;
    }
}
/* Ambiotica-on-Plinky — panel.
 *
 * Play surface (left half) drives the built-in synth; its dry bus feeds the Ambiotica
 * chain (full_chain.h), which runs on core1 in on_dsp() and owns the output (the
 * built-in FX are silenced — Ambiotica IS the FX). See PORT_NOTES.md for the
 * core1-budget story. Build config: amb_config.h (LOOPER_I16) concatenated by
 * amalgamate.sh; per-module flags live in their own files (shimmer/cloud off in
 * microloop.c). Reverb is always the Dattorro plate.
 */
#define PANEL_PAD_COLOR TEAL
#define AMB_SR 32000.0
#define FC_SOFT_CLIP            /* soft-limit the chain output (see full_chain.h) */
/* Attenuate the Plinky synth before the chain: its polyphonic bus sums much hotter
 * than the plugin's single host input, and the whole chain (loop x1.9 makeup, drift
 * regen, layer sums) is tuned around a ~0.18 peak input (see ambiotica-plugin
 * tools/buildup_test.cpp). 0.12 lands the raw poly bus near that nominal level. */
#define AMB_IN_GAIN 0.12f

/* Slider column order (col 8..14). The two loopers sit together (Orbit = main loop,
   Satellite = micro-loop) with the granular scatter after them — grouped for legibility
   rather than strict signal-chain order (looper -> granular -> microloop). */
enum { FX_ORBIT, FX_SATELLITE, FX_CONSTELLATE, FX_TAIL, FX_FLUX, FX_SPECTRA, FX_MIX, FX_N };

struct ambiotica_panel : panel_t {
    looper_t* looper = 0; granular_t* granular = 0; microloop_t* microloop = 0;
    harmony_t* harmony = 0; bloom_t* bloom = 0; drift_t* drift = 0;
    bool dsp_ok = false;

    full_params fx;      /* target macros (set from the sliders in on_ui) */
    full_params fx_sm;   /* per-block-smoothed macros actually fed to the chain (de-click) */
    fc_state    st;
    /* Dattorro reverb + harmony + drift + bloom live here (fast SRAM) — their
     * scattered delay-line access is too slow in PSRAM. Fits the 128 KB panel arena.
     * Looper/micro-loop/granular (big, sequential-ish) stay in PSRAM. */
    unsigned char sram_pool[88 * 1024];

    float sL[BLOCK_SIZE], sR[BLOCK_SIZE], oL[BLOCK_SIZE], oR[BLOCK_SIZE];
    play_surface_t play;
    slider_t       fxslider[FX_N];
    unsigned char  fx_val[FX_N];
    slider_t       fxslider15;                 /* col-15: bipolar Gravity(up)/Drain(down) */
    unsigned char  fx_val15 = 64;              /* 64 = centre / neutral */
    int            key_pos = 0;                /* circle-of-fifths position 0..11 (left buttons) */
    int            mode_sel = 0;             /* 0..4 = Ionian/Aeolian/Dorian/Lydian/Mixolydian (right buttons) */
    bool           eh_flushed = false;         /* Event Horizon: buffers cleared at the bottom (edge) */
    float          grav_sm = 0.f;              /* Gravity macro, ramped ~2 s (plugin gravitySmooth) */
    int            synth_preset = 0;
    unsigned short voices_active = 0, voices_seen = 0;

    /* visualization taps — written in on_dsp (core1 audio), read in on_ui.
       Each reactive slider is a SELF-CALIBRATING meter: env = fast envelope,
       pk = slow-release peak-hold. on_ui maps env/pk -> brightness (meter_bri),
       so every column pulses across the full brightness range regardless of the
       absolute signal level (loopL, micL and granL differ ~10x in magnitude). */
    float        viz_out = 0.f;                                 /* output level (play-surface breathing) */
    float        viz_loop_env = 0.f,  viz_loop_pk = 0.f;       /* Orbit: main-loop emit meter */
    float        viz_micro_env = 0.f, viz_micro_pk = 0.f;      /* Satellite: micro-loop emit meter */
    float        viz_grain_env = 0.f, viz_grain_pk = 0.f;      /* Constellate: granular meter */
    unsigned int viz_loop = 0, viz_micro = 0;                  /* main-loop & micro-loop phase counters */
    unsigned int viz_loop_len = 1, viz_micro_len = 1;          /* their cycle lengths in samples (falling-star clocks) */
    float        shimmer_phase = 0.f;              /* slow LFO for the Tail slider's shimmer */
    float        freeze_phase = 0.f;               /* Satellite freeze indicator: fast 3-spot bounce */

    /* Self-calibrating meter -> slider brightness (q8, 0..256). Maps a fast
       envelope against its own slow peak-hold: idle -> dim floor, emitting ->
       bright, so it pulses at ANY absolute level. gate_ref = the per-channel
       signal scale (its silence threshold). Verified in the desktop harness. */
    static int meter_bri(float env, float pk, float gate_ref) {
        float d = pk < 0.005f ? 0.005f : pk;
        float n = env / d;        if (n > 1.f) n = 1.f;    /* 0..1 pulse (env vs recent peak) */
        float g = pk / gate_ref;  if (g > 1.f) g = 1.f;    /* dim toward silence */
        int b = 36 + (int)(n * g * 220.f);                 /* 36 (idle) .. 256 (peak) */
        if (b < 0) b = 0; if (b > 256) b = 256;
        return b;
    }

    void setup_default_panel_state() override {
        fx_val[FX_ORBIT] = 48; fx_val[FX_CONSTELLATE] = 48; fx_val[FX_SATELLITE] = 32;
        fx_val[FX_TAIL] = 76; fx_val[FX_FLUX] = 40; fx_val[FX_SPECTRA] = 64; fx_val[FX_MIX] = 90;
        memset(&fx, 0, sizeof fx);
        fx.bpm = 120.f; fx.loop_length_bars = 2.f; fx.key = 0; fx.chord = 0; fx.bloom = 0.4f;
        fx.gravity = 0.f; fx.horizon = 1.f;   /* neutral: no gravity, full sustain */
        push_fx_from_ui();
        fx_sm = fx;   /* start the smoother at the target so nothing ramps up from 0 on boot */

        /* Ambiotica IS the FX and owns the output (on_dsp returns true), so do_fx never
         * runs — but zero the synth voices' reverb/delay sends defensively so nothing can
         * bleed into a native bus. */
        set_param_packed(VOICE_PARAM_REVERB_SEND, 0, &synth_presets[synth_preset]);
        set_param_packed(VOICE_PARAM_DELAY_SEND,  0, &synth_presets[synth_preset]);

        g_amb_ps_base = get_psram_ptr(); g_amb_ps_cap = get_psram_size(); g_amb_ps_used = 0;
        g_amb_sr_base = sram_pool;       g_amb_sr_cap = sizeof(sram_pool);  g_amb_sr_used = 0;
        const int sr = (int) AMB_SR;
        const int loopcap = 32 * sr;
        const bool ps = g_amb_ps_cap >= (size_t) 4 * 1024 * 1024;   /* looper 4 MB (+ big modules at high levels) */
        g_amb_region = 1;   /* PSRAM: big buffers (looper/micro/granular; sequential-ish access) */
        if (ps) looper    = looper_create(loopcap, sr);
        if (ps) microloop = microloop_create(sr);
        if (ps) granular  = granular_create(sr);
        g_amb_region = 0;   /* SRAM pool: fast-access modules (dattorro/harmony/drift/bloom) */
        bloom   = bloom_create(sr);
        drift   = drift_create(sr);
        harmony = harmony_create(sr);
        dsp_ok = looper && microloop && granular && bloom && drift && harmony;
        fc_init(&st, 0.7f);
        st.dat = dattorro_create(sr);   /* Dattorro plate (SRAM region); after fc_init zeroes st */
        dsp_ok = dsp_ok && st.dat;
    }

    void push_fx_from_ui() {
        /* Mirrors the plugin's MacroMap.h::deriveStages exactly — same curves and
         * knob DIRECTIONS — so each control behaves identically (timbre aside). */
        const float orbit  = fx_val[FX_ORBIT]       / 127.f;
        const float tex    = fx_val[FX_CONSTELLATE] / 127.f;
        const float sat    = fx_val[FX_SATELLITE]   / 127.f;
        const float tail   = fx_val[FX_TAIL]        / 127.f;
        const float motion = fx_val[FX_FLUX]        / 127.f;
        const float harm   = fx_val[FX_SPECTRA]     / 127.f;

        fx.loop_length_bars = 0.5f + 7.5f * (1.f - orbit);   /* Orbit: REVERSED (up = shorter) */
        fx.loop_layer       = 0.82f;                          /* kLoopBedLayer: constant bed */
        fx.decay            = 0.30f + 0.70f * tail;           /* Tail: reverb decay */
        fx.ring             = tail;                            /* Tail: chord ring length */
        fx.grain_size       = 0.15f + 0.70f * tex;            /* Constellate: grain size */
        fx.scatter          = tex;                            /* Constellate: scatter */
        fx.mod_depth        = motion;                          /* Flux */
        fx.mod_rate         = 0.10f + 0.80f * motion;
        fx.drift_amt        = motion;
        fx.bloom            = 0.60f;                           /* kBakedBloom: constant swell */
        fx.spectra          = harm;                            /* Spectra: chord amount */
        fx.micro_hold       = sat;                             /* Satellite: hold -> Freeze at top */
        fx.micro_bars       = 0.125f + 1.875f * (1.f - sat);  /* Satellite: micro length, REVERSED */
        fx.mix              = fx_val[FX_MIX] / 127.f;          /* Mix: dry/wet */

        /* Gravity + Event Horizon macros (mirror MacroMap::deriveStages). Gravity is the
         * master "collapse to the drone": as it rises it lerps every stage toward its
         * drone target — the loop bed swells, reverb maxes, the micro-loop freezes, the
         * chord rings, grains thicken. Event Horizon lerps them back toward "clear",
         * applied LAST so it overrides Gravity. grav_sm ramps over ~2 s (plugin value). */
        grav_sm += 0.010f * (fx.gravity - grav_sm);            /* ~2 s (plugin gravitySmooth) */
        { float gd = fx.gravity - grav_sm; if (gd < 5e-4f && gd > -5e-4f) grav_sm = fx.gravity; }  /* settle so fc_push_params can gate off */
        const float gg = grav_sm < 0.f ? 0.f : (grav_sm > 1.f ? 1.f : grav_sm);
        #define AMB_LERP(a,b,t) ((a) + ((b) - (a)) * (t))
        fx.loop_layer = AMB_LERP(fx.loop_layer, 0.97f, gg);
        fx.decay      = AMB_LERP(fx.decay,      1.00f, gg);
        fx.drift_amt  = AMB_LERP(fx.drift_amt,  0.85f, gg);
        fx.micro_hold = AMB_LERP(fx.micro_hold, 1.00f, gg);
        fx.spectra    = AMB_LERP(fx.spectra,    0.60f, gg);
        fx.ring       = AMB_LERP(fx.ring,       1.00f, gg);
        fx.grain_size = AMB_LERP(fx.grain_size, 0.70f, gg);
        fx.scatter    = AMB_LERP(fx.scatter,    0.55f, gg);
        fx.mod_depth  = AMB_LERP(fx.mod_depth,  0.55f, gg);
        float clear = 1.0f - fx.horizon; if (clear < 0.f) clear = 0.f;
        if (clear > 0.f) {
            fx.loop_layer = AMB_LERP(fx.loop_layer, 0.08f, clear);
            fx.micro_hold = AMB_LERP(fx.micro_hold, 0.00f, clear);
            fx.ring       = AMB_LERP(fx.ring,       0.00f, clear);
            fx.decay      = AMB_LERP(fx.decay,      0.00f, clear);
            fx.drift_amt  = AMB_LERP(fx.drift_amt,  0.00f, clear);
        }
        #undef AMB_LERP
    }

    static void note_cb(void* user, int voice, int note, unsigned char vel, finger_t f) {
        ambiotica_panel* self = (ambiotica_panel*)user;
        if (voice < 0 || voice >= 16) return;
        unsigned short bit = (unsigned short)(1u << voice);
        bool is_new = (self->voices_active & bit) == 0;
        int pnote = note - 12; if (pnote < 0) pnote = 0;   /* play surface 1 octave lower */
        play_synth(voice, self->synth_preset, (int)vel, pnote << 8, is_new);
        self->voices_seen |= bit;
        (void)f;
    }

    /* play-surface glow: breathes with the wash. (Grain activity now pulses the
       Constellate slider instead of sparkling here — see on_ui.) */
    static unsigned char viz_brightness(void* user, int si, int sp, int x, int y, int note) {
        (void)si; (void)sp; (void)note; (void)x; (void)y;
        ambiotica_panel* self = (ambiotica_panel*)user;
        int b = (int)(self->viz_out * 28.f);                       /* breathing base glow */
        if (b < 0) b = 0; if (b > 255) b = 255;
        return (unsigned char)b;
    }

    void on_ui(int dt_us) override {
        leds_clear();
#ifdef AMB_PROFILE
        /* Per-stage core1 timing (avg us/block). Prints UNCONDITIONALLY ~8x/sec so it's a
         * heartbeat too: if this never appears, printf/on_ui isn't reaching the console;
         * if it shows (n=0) the DSP block isn't completing; otherwise it's the breakdown. */
        static unsigned prof_ctr = 0;
        if ((++prof_ctr % 30) == 0) {
            unsigned nn = g_stage_n ? g_stage_n : 1;
            printf("STG loop=%u gran=%u mic=%u rev=%u harm=%u mix=%u push=%u  (n=%u)\n",
                   g_stage_us[0]/nn, g_stage_us[1]/nn, g_stage_us[2]/nn, g_stage_us[3]/nn,
                   g_stage_us[4]/nn, g_stage_us[5]/nn, g_stage_us[6]/nn, g_stage_n);
            for (int s = 0; s < 7; s++) g_stage_us[s] = 0;
            g_stage_n = 0;
        }
#endif
        voices_seen = 0;
        /* Play-surface colour: hue = key (root), shade/brightness = mode — so the
           left/right buttons visibly recolour the surface as they move the key around
           the circle of fifths / change the mode. */
        /* Play-surface hue is reserved to 8..15 so it can never collide with a macro
           slider (those use hues 0..6, Orbit = 0) — the two halves must stay tellable
           apart. Brightness still tracks the chord, hue still tracks the key. */
        uint32_t keycol = palette[(7 + mode_sel * 2) & 15][8 + (fx.key & 7)];
        /* play surface, now with an activity glow/sparkle via the brightness cb */
        /* 4-voice polyphony: the synth renders inside the same core1 2ms budget
         * as our FX; 8 voices' render time pushed us over. 4 leaves headroom for
         * the full chain and is plenty for an ambient wash. */
        /* Quartal, always-in-key play surface: 8 strings tuned in DIATONIC 4THS
           (interval_degrees = 3 scale steps) within the selected key + mode, so every
           adjacent cluster is an open, in-key chord and sliding up a string walks the
           scale. Root register follows the circle-of-fifths key; the mode (right buttons)
           picks the scale, so the whole surface + the Spectra wash share one tonal world.
           Scale bitmask, bit N = N semitones above the root. */
        static const uint16_t kModeScale[5] = {
            2741,   /* Ionian / major    0,2,4,5,7,9,11 */
            1453,   /* Aeolian / minor   0,2,3,5,7,8,10 */
            1709,   /* Dorian            0,2,3,5,7,9,10 */
            2773,   /* Lydian            0,2,4,6,7,9,11 */
            1717,   /* Mixolydian        0,2,4,5,7,9,10 */
        };
        int msel = (mode_sel < 0 || mode_sel > 4) ? 0 : mode_sel;
        play.do_play_surface(0, 0, 8, 16, 4, DIMMEST(keycol), keycol, 48 + fx.key, 3, note_cb, this,
                             VERTICAL | SHOW_BACKGROUND | STRINGOPHONIC_MONO, kModeScale[msel], fx.key,
                             viz_brightness, this);
        unsigned short released = (unsigned short)(voices_active & ~voices_seen);
        for (int v = 0; v < 16; v++) if (released & (1u << v)) synth_note_up(v);
        voices_active = voices_seen;
        static const char* nm[FX_N] = { "Orbit","Satellite","Constellate","Tail","Flux","Spectra","Mix" };
        /* Tail + Flux flash IN SYNC on one LFO whose rate tracks the Flux mod rate — the
           modulation pair, at a speed distinct from the loop meters. */
        float tail = fx_val[FX_TAIL] / 127.f, flux = fx_val[FX_FLUX] / 127.f;
        shimmer_phase += (float)dt_us * 1e-6f * (0.35f + fx.mod_rate * 2.2f); shimmer_phase -= (float)(int)shimmer_phase;
        float shTri   = shimmer_phase < 0.5f ? shimmer_phase * 2.f : 2.f - shimmer_phase * 2.f;
        float shimmer = shTri * shTri * (3.f - 2.f * shTri);
        freeze_phase += (float)dt_us * 1e-6f * 2.5f; freeze_phase -= (float)(int)freeze_phase;   /* Satellite freeze bounce */
        for (int i = 0; i < FX_N; i++) {
            /* Reactive sliders pulse their colour; Spectra & Mix stay steady.
               (the *N.f gains below are the obvious brightness tuning knobs) */
            int bri = 256;
            switch (i) {
                case FX_ORBIT:       bri = meter_bri(viz_loop_env,  viz_loop_pk,  0.02f); break;  /* pulse: main loop emitting */
                case FX_SATELLITE:   bri = meter_bri(viz_micro_env, viz_micro_pk, 0.01f); break;  /* pulse: micro-loop emitting */
                case FX_CONSTELLATE: bri = meter_bri(viz_grain_env, viz_grain_pk, 0.01f); break;  /* pulse: grains firing */
                case FX_TAIL:        bri = 60 + (int)(tail * shimmer * 196.f); break;  /* Tail + Flux shimmer in sync */
                case FX_FLUX:        bri = 60 + (int)(flux * shimmer * 196.f); break;
            }
            if (bri < 0) bri = 0; if (bri > 256) bri = 256;
            fxslider[i].simple_slider(8 + i, 0, 16, VERTICAL | SHOW_STEM,
                                      fade_col(palette[8][i], bri), 0, 127, fx_val[i], nm[i]);
            fx_val[i] = (unsigned char)last_widget_new_value();

            /* Orbit & Satellite each carry a white "star" that falls down its own column
               once per loop cycle — a per-column clock. When Satellite is at FREEZE the
               micro-loop isn't cycling, so the star stops falling and instead bounces
               fast up/down between three rows (held in place) to read as "frozen". */
            if (i == FX_SATELLITE && fx.micro_hold >= 0.9f) {
                int step = (int)(freeze_phase * 4.f) & 3;                 /* 0..3 */
                int off  = (step == 1) ? -1 : (step == 3) ? 1 : 0;        /* centre, up, centre, down */
                set_led(8 + i, 7 + off, fade_col(WHITE, 240));
            } else if (i == FX_ORBIT || i == FX_SATELLITE) {
                unsigned int phase = (i == FX_ORBIT) ? viz_loop     : viz_micro;
                unsigned int len   = (i == FX_ORBIT) ? viz_loop_len : viz_micro_len;
                int row = len ? (int)(((float)phase / (float)len) * 15.f) : 0;
                if (row < 0) row = 0; if (row > 15) row = 15;
                int sb = 130 + (bri - 36) / 2;  if (sb > 256) sb = 256;
                set_led(8 + i, row, fade_col(WHITE, sb));
            }

        }
        push_fx_from_ui();

        /* col-15: bipolar Gravity (up) / Event Horizon (down). Neutral = centre. Call
           simple_slider for the touch/value, then draw our own bipolar column over it. */
        int gd = (int)fx_val15 - 64;
        fxslider15.simple_slider(15, 0, 16, VERTICAL | SHOW_STEM,
                                 fade_col(gd >= 0 ? GREEN : RED, 256), 0, 127, fx_val15, "Grav/Drain");
        fx_val15 = (unsigned char)last_widget_new_value();
        gd = (int)fx_val15 - 64;
        /* Bipolar fill that GROWS from the centre (rows 7,8, the true middle of 0..15):
           GREEN filling up as it's scrolled up (Gravity), RED filling down as scrolled down
           (Event Horizon). All lit pads are coloured. Only at the exact centre position do
           the two middle LEDs show WHITE, to mark neutral. */
        for (int y = 0; y < 16; y++) {
            uint32_t c = 0;                                       /* off */
            if (gd == 0) {
                if (y == 7 || y == 8) c = LED_RGB(20, 20, 20);   /* neutral: white centre marker */
            } else if (gd > 0) {                                 /* Gravity: green fill, rows 7..0 */
                int topRow = 7 - (gd * 7) / 63;
                if (y >= topRow && y <= 7) c = fade_col(GREEN, 256);
            } else {                                             /* drain: red fill, rows 8..15 */
                int botRow = 8 + ((-gd) * 7) / 64;
                if (y >= 8 && y <= botRow) c = fade_col(RED, 256);
            }
            set_led(15, y, c);
        }
        fx.gravity = gd > 0 ? (float)gd / 63.f : 0.f;          /* up   -> gravity 0..1 */
        fx.horizon = gd < 0 ? (float)fx_val15 / 64.f : 1.f;    /* down -> horizon 1..0 (drain) */
    }

    /* Core-1 audio hook (new API). Base renders the synth into mix_buffers_out;
     * we run Ambiotica on its dry stereo bus, write final int16 to audiobuf_out,
     * and return true to own the output (bypass the built-in FX — Ambiotica IS
     * the FX). Running on core1 means an overrun crackles rather than locking the
     * UI/USB, so this is where the heavy chain belongs.
     *
     * v1: dry bus only. The synth's reverb/delay SEND buses are not captured yet
     * (their half-rate format needs confirming); if a preset routes signal to
     * them it'll sound thinner. v1.1 will route reverbsend -> reverb input and
     * delaysend -> micro-loop input. */
    bool on_dsp(const int16_t* audiobuf_in, int16_t* audiobuf_out,
                mix_buffers_t* mix_buffers_out) override {
        panel_t::on_dsp(audiobuf_in, audiobuf_out, mix_buffers_out);   /* render synth -> dry */

        if (!dsp_ok) {                                   /* passthrough (alloc failed) */
            for (int i = 0; i < BLOCK_SIZE * 2; i++) {
                int v = mix_buffers_out->dry[i];
                audiobuf_out[i] = (int16_t)(v < -32768 ? -32768 : v > 32767 ? 32767 : v);
            }
            return true;
        }

        const float k = (1.0f / 32768.0f) * AMB_IN_GAIN;   /* headroom for polyphony */
        for (int i = 0; i < BLOCK_SIZE; i++) {
            sL[i] = mix_buffers_out->dry[2*i]   * k;
            sR[i] = mix_buffers_out->dry[2*i+1] * k;
        }

        /* Per-block macro smoothing (~30 ms). The plugin gets smooth param values
           from the host; the Plinky sliders deliver coarse 0..127 steps, so pushing
           them straight to the chain clicks (Tail room-size, Spectra amount, micro
           hold, ...). Ramp the continuous macros toward their targets; length +
           discrete params pass through (their DSP crossfades/snaps handle those). */
        const float ps = 0.06f;
        /* Ramp toward the target, then SNAP when within a deadband so fx_sm settles
           bit-exactly on fx — otherwise the one-pole asymptote never equals the
           target and fc_push_params' memcmp gate would re-run powf/expf every block
           (the DSP budget is tight). During an active move it re-pushes as intended. */
        #define AMB_SM(f) { float d_ = fx.f - fx_sm.f; fx_sm.f += ps * d_; \
                            if (d_ < 5e-4f && d_ > -5e-4f) fx_sm.f = fx.f; }
        AMB_SM(mix); AMB_SM(loop_layer); AMB_SM(grain_size); AMB_SM(scatter);
        AMB_SM(micro_hold); AMB_SM(decay); AMB_SM(mod_depth); AMB_SM(mod_rate);
        AMB_SM(bloom); AMB_SM(drift_amt); AMB_SM(spectra); AMB_SM(ring);
        AMB_SM(gravity); AMB_SM(horizon);
        #undef AMB_SM
        fx_sm.loop_length_bars = fx.loop_length_bars; fx_sm.micro_bars = fx.micro_bars;
        fx_sm.bpm = fx.bpm; fx_sm.key = fx.key; fx_sm.chord = fx.chord;

        /* Event Horizon: at the BOTTOM of col-15 the drain ends in a one-shot flush that
           clears the content buffers, so bringing the slider back up starts empty.
           Gate on the SMOOTHED horizon, not the raw tap: by the time it settles to the
           bottom the drain has already silenced the loop and micro-loop (micro hold has
           reached 0), so the flush clears quiet buffers. Flushing on the raw tap instead
           cleared them mid-drain, into a still-live signal that instantly refilled — the
           short frozen-loop "buzz". Hysteresis so it can't re-fire on the edge; the
           reverb is left out so its tail decays gracefully rather than being cut. */
        if (fx_sm.horizon < 0.04f) {
            if (!eh_flushed) {
                if (looper)    looper_reset(looper);
                if (microloop) microloop_reset(microloop);
                if (granular)  granular_reset(granular);
                if (harmony)   harmony_reset(harmony);
                if (bloom)     bloom_reset(bloom);
                if (drift)     drift_reset(drift);
                eh_flushed = true;
            }
        } else if (fx_sm.horizon > 0.10f) {
            eh_flushed = false;
        }

        fc_render_block(&st, looper, granular, microloop, harmony, bloom, drift,
                        &fx_sm, AMB_SR, sL, sR, oL, oR, BLOCK_SIZE);

        for (int i = 0; i < BLOCK_SIZE; i++) {
            int l = (int)(oL[i] * 32767.0f), r = (int)(oR[i] * 32767.0f);
            audiobuf_out[2*i]   = (int16_t)(l < -32768 ? -32768 : l > 32767 ? 32767 : l);
            audiobuf_out[2*i+1] = (int16_t)(r < -32768 ? -32768 : r > 32767 ? 32767 : r);
        }

        /* cheap visualization taps: output level (breathing) + per-channel block
           peaks for the main loop, micro-loop and granular. */
        float op = 0.f, gp = 0.f, lp = 0.f, mp = 0.f;
        for (int i = 0; i < BLOCK_SIZE; i++) {
            float a = oL[i]       < 0.f ? -oL[i]       : oL[i];       if (a > op) op = a;
            float g = st.granL[i] < 0.f ? -st.granL[i] : st.granL[i]; if (g > gp) gp = g;
            float l = st.loopL[i] < 0.f ? -st.loopL[i] : st.loopL[i]; if (l > lp) lp = l;
            float m = st.micL[i]  < 0.f ? -st.micL[i]  : st.micL[i];  if (m > mp) mp = m;
        }
        viz_out       = viz_out * 0.9f + op * 0.1f;
        /* per-channel meter: fast envelope + slow-release peak-hold (see meter_bri) */
        viz_loop_env  = viz_loop_env  * 0.90f + lp * 0.10f;  viz_loop_pk  = lp > viz_loop_pk  ? lp : viz_loop_pk  * 0.9990f;
        viz_micro_env = viz_micro_env * 0.90f + mp * 0.10f;  viz_micro_pk = mp > viz_micro_pk ? mp : viz_micro_pk * 0.9990f;
        viz_grain_env = viz_grain_env * 0.90f + gp * 0.10f;  viz_grain_pk = gp > viz_grain_pk ? gp : viz_grain_pk * 0.9990f;
        int llen = (int)(fx.loop_length_bars * 4.f * 60.f / (fx.bpm > 0.f ? fx.bpm : 120.f) * (float)AMB_SR);
        if (llen < 1) llen = 1;
        viz_loop_len = (unsigned)llen;
        viz_loop += BLOCK_SIZE; if (viz_loop >= (unsigned)llen) viz_loop -= (unsigned)llen;
        int mlen = (int)(fx.micro_bars * 4.f * 60.f / (fx.bpm > 0.f ? fx.bpm : 120.f) * (float)AMB_SR);
        if (mlen < 1) mlen = 1;
        viz_micro_len = (unsigned)mlen;
        /* Freeze the micro-loop star when Satellite is at/near the top (held shimmer). */
        if (fx.micro_hold < 0.9f) { viz_micro += BLOCK_SIZE; if (viz_micro >= (unsigned)mlen) viz_micro -= (unsigned)mlen; }
        return true;
    }

    /* Physical side buttons: LEFT pair steps the KEY around the circle of fifths
       (+1 = up a fifth = +7 semitones); RIGHT pair steps the MODE (Ionian/Aeolian/
       Dorian/Lydian/Mixolydian), which sets the surface scale AND the Spectra wash
       tonic. The play-surface colour follows (hue = key, shade = mode). Unhandled
       buttons fall through to the system (BPM / pages). */
    void on_click(uint8_t button_mask) override {
        bool handled = false;
        if ((button_mask & BTN_BIT_LUP)   && button_clicked(BUTTON_LUP))   { key_pos    = (key_pos + 1)  % 12; handled = true; }
        if ((button_mask & BTN_BIT_LDOWN) && button_clicked(BUTTON_LDOWN)) { key_pos    = (key_pos + 11) % 12; handled = true; }
        if ((button_mask & BTN_BIT_RUP)   && button_clicked(BUTTON_RUP))   { mode_sel = (mode_sel + 1) % 5; handled = true; }
        if ((button_mask & BTN_BIT_RDOWN) && button_clicked(BUTTON_RDOWN)) { mode_sel = (mode_sel + 4) % 5; handled = true; }
        if (handled) {
            fx.key   = (key_pos * 7) % 12;   /* circle of fifths -> root semitone offset */
            fx.chord = mode_sel;
        } else {
            panel_t::on_click(button_mask);
        }
    }

    bool on_serialise(serialiser_t& s, int version) override {
        /* TODO: persist fx_val[], synth_preset, fx.key/chord via save_and_load.h field macros */
        return panel_t::on_serialise(s, version);
    }
};
